import React, { createContext, useContext, useEffect, useState } from 'react';
import { onAuthStateChanged, User } from 'firebase/auth';
import { doc, getDoc } from 'firebase/firestore';
import { auth, db } from '../core/firebase';
import { UserProfile } from '../core/types';

interface AuthContextType {
  user: User | null;
  profile: UserProfile | null;
  loading: boolean;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      setUser(firebaseUser);
      if (firebaseUser) {
        try {
          const docRef = doc(db, 'users', firebaseUser.uid);
          const docSnap = await getDoc(docRef);
          if (docSnap.exists()) {
            setProfile(docSnap.data() as UserProfile);
          }
        } catch (error) {
          console.error("Error fetching user profile:", error);
        }
      } else {
        setProfile(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const logout = async () => {
    await auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, profile, loading, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from './AuthProvider';
import { UserRole } from '../core/types';

interface AuthGuardProps {
  children: React.ReactNode;
  allowedRole?: UserRole;
}

const AuthGuard: React.FC<AuthGuardProps> = ({ children, allowedRole }) => {
  const { user, profile, loading } = useAuth();
  const location = useLocation();

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
      </div>
    );
  }

  if (!user) {
    return <Navigate to="/login" state={{ from: location }} replace />;
  }

  if (allowedRole && profile?.role !== allowedRole) {
    const fallback = profile?.role === 'admin' ? '/admin' : '/student';
    return <Navigate to={fallback} replace />;
  }

  return <>{children}</>;
};

export default AuthGuard;

import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from './AuthProvider';

const RoleRouter: React.FC = () => {
  const { profile, loading } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    if (!loading && profile) {
      if (profile.role === 'admin') {
        navigate('/admin');
      } else {
        navigate('/student');
      }
    }
  }, [profile, loading, navigate]);

  return (
    <div className="min-h-screen flex items-center justify-center">
      <div className="animate-pulse text-indigo-600 font-medium">Redirecting based on role...</div>
    </div>
  );
};

export default RoleRouter;

import { 
  collection, 
  addDoc, 
  getDocs, 
  getDoc, 
  doc, 
  query, 
  where, 
  updateDoc, 
  deleteDoc,
  serverTimestamp,
  orderBy,
  limit
} from 'firebase/firestore';
import { db } from '../core/firebase';
import { Quiz, Question } from '../core/types';

export const quizService = {
  async createQuiz(data: Partial<Quiz>, uid: string): Promise<string> {
    const docRef = await addDoc(collection(db, 'quizzes'), {
      ...data,
      createdBy: uid,
      createdAt: Date.now(),
      published: false,
      totalQuestions: 0
    });
    return docRef.id;
  },

  async getPublishedQuizzes(): Promise<Quiz[]> {
    const q = query(
      collection(db, 'quizzes'), 
      where('published', '==', true),
      orderBy('createdAt', 'desc')
    );
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Quiz));
  },

  async getAllQuizzes(): Promise<Quiz[]> {
    const q = query(collection(db, 'quizzes'), orderBy('createdAt', 'desc'));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Quiz));
  },

  async getQuiz(id: string): Promise<Quiz | null> {
    const docSnap = await getDoc(doc(db, 'quizzes', id));
    return docSnap.exists() ? ({ id: docSnap.id, ...docSnap.data() } as Quiz) : null;
  },

  async updateQuiz(id: string, data: Partial<Quiz>) {
    await updateDoc(doc(db, 'quizzes', id), data);
  },

  async deleteQuiz(id: string) {
    await deleteDoc(doc(db, 'quizzes', id));
  },

  async addQuestion(quizId: string, data: Partial<Question>) {
    const docRef = await addDoc(collection(db, 'questions'), {
      ...data,
      quizId
    });

    // Update question count in quiz
    const quiz = await this.getQuiz(quizId);
    if (quiz) {
      await this.updateQuiz(quizId, { totalQuestions: (quiz.totalQuestions || 0) + 1 });
    }
    return docRef.id;
  },

  async getQuestions(quizId: string): Promise<Question[]> {
    const q = query(collection(db, 'questions'), where('quizId', '==', quizId));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Question));
  }
};

import { 
  collection, 
  addDoc, 
  getDocs, 
  query, 
  where, 
  orderBy 
} from 'firebase/firestore';
import { db } from '../core/firebase';
import { Submission } from '../core/types';

export const submissionService = {
  async submitExam(data: Omit<Submission, 'id'>): Promise<string> {
    const docRef = await addDoc(collection(db, 'submissions'), {
      ...data,
      timestamp: Date.now()
    });
    return docRef.id;
  },

  async getStudentResults(studentId: string): Promise<Submission[]> {
    const q = query(
      collection(db, 'submissions'), 
      where('studentId', '==', studentId),
      orderBy('completedAt', 'desc')
    );
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
  },

  async getQuizResults(quizId: string): Promise<Submission[]> {
    const q = query(
      collection(db, 'submissions'), 
      where('quizId', '==', quizId),
      orderBy('score', 'desc')
    );
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
  }
};

