import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Navbar, Container, Card } from '../ui/Layout';
import { quizService } from '../services/quizService';
import { submissionService } from '../services/submissionService';
import { Quiz, Question } from '../core/types';
import { useAuth } from '../auth/AuthProvider';

const QuizRoom: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();

  const [quiz, setQuiz] = useState<Quiz | null>(null);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [timeLeft, setTimeLeft] = useState(0);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [examStarted, setExamStarted] = useState(false);

  const timerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    if (id) {
      loadQuiz(id);
    }
  }, [id]);

  useEffect(() => {
    if (examStarted && timeLeft > 0) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            clearInterval(timerRef.current!);
            handleSubmit();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [examStarted, timeLeft]);

  const loadQuiz = async (quizId: string) => {
    try {
      const qz = await quizService.getQuiz(quizId);
      if (!qz || !qz.published) {
        navigate('/student');
        return;
      }
      const qs = await quizService.getQuestions(quizId);
      setQuiz(qz);
      setQuestions(qs);
      setTimeLeft(qz.timeLimit * 60);
    } catch (error) {
      console.error(error);
      navigate('/student');
    } finally {
      setLoading(false);
    }
  };

  const handleSelect = (optionIdx: number) => {
    const currentQ = questions[currentIndex];
    setAnswers(prev => ({ ...prev, [currentQ.id]: optionIdx }));
  };

  const handleSubmit = async () => {
    if (!quiz || !profile || submitting) return;
    setSubmitting(true);

    // Calculate Score
    let score = 0;
    questions.forEach(q => {
      if (answers[q.id] === q.correctOptionIndex) {
        score++;
      }
    });

    try {
      await submissionService.submitExam({
        quizId: quiz.id,
        studentId: profile.uid,
        studentName: profile.displayName,
        score,
        totalPossible: questions.length,
        startedAt: Date.now() - (quiz.timeLimit * 60 - timeLeft) * 1000,
        completedAt: Date.now(),
        answers
      });
      alert(`Exam Submitted! Your Score: ${score}/${questions.length}`);
      navigate('/student');
    } catch (err) {
      console.error(err);
      setSubmitting(false);
    }
  };

  if (loading) return <div className="h-screen flex items-center justify-center">Loading exam module...</div>;

  if (!examStarted) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <Card className="max-w-xl w-full p-12 text-center bg-white">
           <i className="fas fa-shield-alt text-6xl text-indigo-600 mb-6"></i>
           <h1 className="text-3xl font-bold mb-4">{quiz?.title}</h1>
           <p className="text-slate-600 mb-8">{quiz?.description}</p>
           <div className="bg-slate-50 p-6 rounded-2xl mb-8 flex justify-around text-sm font-bold text-slate-500 uppercase">
             <div className="flex flex-col items-center">
                <span className="text-slate-900 text-lg">{quiz?.timeLimit} Min</span>
                <span>Time Limit</span>
             </div>
             <div className="flex flex-col items-center">
                <span className="text-slate-900 text-lg">{questions.length}</span>
                <span>Questions</span>
             </div>
           </div>
           <button 
             onClick={() => setExamStarted(true)} 
             className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-xl hover:bg-indigo-700 transition shadow-lg"
           >
             Begin Examination
           </button>
        </Card>
      </div>
    );
  }

  const currentQ = questions[currentIndex];
  const formatTime = (s: number) => {
    const m = Math.floor(s / 60);
    const rs = s % 60;
    return `${m}:${rs < 10 ? '0' : ''}${rs}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <nav className="bg-white border-b sticky top-0 z-50">
        <Container>
          <div className="flex items-center justify-between py-2">
            <div>
               <h2 className="font-bold text-slate-900">{quiz?.title}</h2>
               <p className="text-xs text-slate-500">Question {currentIndex + 1} of {questions.length}</p>
            </div>
            <div className={`px-4 py-2 rounded-xl font-mono text-xl font-bold flex items-center ${timeLeft < 300 ? 'bg-red-50 text-red-600' : 'bg-indigo-50 text-indigo-600'}`}>
               <i className="far fa-clock mr-2"></i> {formatTime(timeLeft)}
            </div>
            <button 
              onClick={() => { if(confirm("Submit Exam now?")) handleSubmit(); }}
              className="bg-red-600 text-white px-4 py-2 rounded-lg text-sm font-bold"
            >
              Submit
            </button>
          </div>
        </Container>
      </nav>

      <Container>
        <div className="max-w-3xl mx-auto mt-12">
          <Card className="p-8 mb-8">
            <h3 className="text-2xl font-bold text-slate-900 mb-8 leading-relaxed">
              {currentQ.text}
            </h3>
            <div className="space-y-4">
              {currentQ.options.map((opt, i) => (
                <button
                  key={i}
                  onClick={() => handleSelect(i)}
                  className={`w-full p-5 text-left rounded-2xl border-2 transition font-medium flex items-center justify-between group ${answers[currentQ.id] === i ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-100 hover:border-indigo-300 text-slate-700'}`}
                >
                  <span>{opt}</span>
                  <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${answers[currentQ.id] === i ? 'border-white' : 'border-slate-200'}`}>
                    {answers[currentQ.id] === i && <div className="w-3 h-3 bg-white rounded-full"></div>}
                  </div>
                </button>
              ))}
            </div>
          </Card>

          <div className="flex justify-between items-center">
            <button 
              onClick={() => setCurrentIndex(prev => Math.max(0, prev - 1))}
              disabled={currentIndex === 0}
              className="flex items-center text-slate-600 font-bold disabled:opacity-30 p-3"
            >
              <i className="fas fa-chevron-left mr-2"></i> Previous
            </button>
            <div className="flex space-x-1">
              {questions.map((_, i) => (
                <div key={i} className={`w-2 h-2 rounded-full ${i === currentIndex ? 'bg-indigo-600 w-4' : (answers[questions[i].id] !== undefined ? 'bg-indigo-300' : 'bg-slate-200')} transition-all`}></div>
              ))}
            </div>
            {currentIndex < questions.length - 1 ? (
              <button 
                onClick={() => setCurrentIndex(prev => prev + 1)}
                className="flex items-center text-indigo-600 font-bold p-3"
              >
                Next <i className="fas fa-chevron-right ml-2"></i>
              </button>
            ) : (
              <button 
                onClick={handleSubmit}
                className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold shadow-lg shadow-indigo-200"
              >
                Final Submit
              </button>
            )}
          </div>
        </div>
      </Container>
    </div>
  );
};

export default QuizRoom;

