import { auth, db } from "../core/firebase";
import {
  signInWithEmailAndPassword,
  createUserWithEmailAndPassword,
  updateProfile,
} from "firebase/auth";
import { doc, setDoc, serverTimestamp } from "firebase/firestore";
import { UserRole } from "../core/types";

/**
 * Translate Firebase Auth errors into user-friendly messages as requested.
 */
const translateError = (code: string): string => {
  switch (code) {
    case "auth/user-not-found":
    case "auth/wrong-password":
    case "auth/invalid-credential":
      return "Password or Email Incorrect";
    case "auth/email-already-in-use":
      return "User already exists. Sign in?";
    case "auth/weak-password":
      return "Password is too weak.";
    case "auth/invalid-email":
      return "Invalid email address.";
    default:
      return "An unexpected error occurred. Please try again.";
  }
};

export const authService = {
  /**
   * Log in an existing user
   */
  async login(email: string, pass: string) {
    try {
      const credential = await signInWithEmailAndPassword(auth, email, pass);
      return credential.user;
    } catch (error: any) {
      throw new Error(translateError(error.code));
    }
  },

  /**
   * Sign up a new student
   * Flow: Auth account -> Firestore profile (default role: student)
   */
  async signup(email: string, pass: string, name: string) {
    try {
      const credential = await createUserWithEmailAndPassword(auth, email, pass);
      const user = credential.user;

      // Update Auth display name
      await updateProfile(user, { displayName: name });

      // Create Firestore profile document
      // Role is strictly defaulted to 'student' for safety
      await setDoc(doc(db, "users", user.uid), {
        uid: user.uid,
        displayName: name,
        email: email,
        role: "student" as UserRole,
        createdAt: serverTimestamp(),
      });

      return user;
    } catch (error: any) {
      throw new Error(translateError(error.code));
    }
  },
};

import React, { createContext, useContext, useEffect, useState } from "react";
import { auth, db } from "../core/firebase";
import { onAuthStateChanged, User } from "firebase/auth";
import { doc, getDoc } from "firebase/firestore";
import { UserRole, UserProfile } from "../core/types";

interface AuthContextType {
  user: User | null;
  profile: UserProfile | null;
  role: UserRole | null;
  loading: boolean;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Listen for authentication state changes
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      setLoading(true);
      setUser(firebaseUser);

      if (firebaseUser) {
        try {
          // Source of truth for identity + authority is Firestore
          const docRef = doc(db, "users", firebaseUser.uid);
          const docSnap = await getDoc(docRef);

          if (docSnap.exists()) {
            const data = docSnap.data() as UserProfile;
            setProfile(data);
            setRole(data.role);
          } else {
            console.warn("User authenticated but no Firestore profile found.");
            setProfile(null);
            setRole(null);
          }
        } catch (error) {
          console.error("Critical error resolving user role:", error);
          setProfile(null);
          setRole(null);
        }
      } else {
        setProfile(null);
        setRole(null);
      }

      setLoading(false);
    });

    // Cleanup listener on unmount
    return () => unsubscribe();
  }, []);

  const logout = async () => {
    await auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, profile, role, loading, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};

