      orderBy('createdAt', 'desc')
    );
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Quiz));
  },

  /**
   * For Admins: Fetch all exams (Drafts + Live)
   */
  async getAllQuizzes(): Promise<Quiz[]> {
    const q = query(collection(db, 'quizzes'), orderBy('createdAt', 'desc'));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Quiz));
  },

  /**
   * Real-time subscription for dashboards
   */
  subscribeToQuizzes(callback: (quizzes: Quiz[]) => void) {
    const q = query(collection(db, 'quizzes'), orderBy('createdAt', 'desc'));
    return onSnapshot(q, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Quiz));
      callback(data);
    });
  },

  async getQuiz(id: string): Promise<Quiz | null> {
    const docSnap = await getDoc(doc(db, 'quizzes', id));
    return docSnap.exists() ? ({ id: docSnap.id, ...docSnap.data() } as Quiz) : null;
  },

  async createQuiz(data: Partial<Quiz>, uid: string): Promise<string> {
    const docRef = await addDoc(collection(db, 'quizzes'), {
      ...data,
      createdBy: uid,
      createdAt: Date.now(),
      published: false,
      totalQuestions: 0
    });
    return docRef.id;
  },

  async updateQuiz(id: string, data: Partial<Quiz>): Promise<void> {
    await updateDoc(doc(db, 'quizzes', id), data);
  },

  async deleteQuiz(id: string): Promise<void> {
    await deleteDoc(doc(db, 'quizzes', id));
  }
};

import { 
  collection, 
  addDoc, 
  getDocs, 
  query, 
  where, 
  doc,
  updateDoc,
  deleteDoc
} from 'firebase/firestore';
import { db } from '../core/firebase';
import { Question } from '../core/types';
import { quizService } from './quizService';

/**
 * questionService - Quiz Content Management
 * Ensures questions are loaded efficiently per exam.
 */
export const questionService = {
  /**
   * Load all questions for a specific quiz
   */
  async getQuestionsByQuiz(quizId: string): Promise<Question[]> {
    const q = query(collection(db, 'questions'), where('quizId', '==', quizId));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Question));
  },

  /**
   * Add a new question and update the parent quiz count
   */
  async addQuestion(quizId: string, data: Partial<Question>): Promise<string> {
    const docRef = await addDoc(collection(db, 'questions'), {
      ...data,
      quizId
    });

    // Update question count in parent quiz
    const quiz = await quizService.getQuiz(quizId);
    if (quiz) {
      await quizService.updateQuiz(quizId, { totalQuestions: (quiz.totalQuestions || 0) + 1 });
    }
    return docRef.id;
  },

  async updateQuestion(id: string, data: Partial<Question>): Promise<void> {
    await updateDoc(doc(db, 'questions', id), data);
  },

  async deleteQuestion(id: string, quizId: string): Promise<void> {
    await deleteDoc(doc(db, 'questions', id));
    // Optionally decrement count
    const quiz = await quizService.getQuiz(quizId);
    if (quiz) {
      await quizService.updateQuiz(quizId, { totalQuestions: Math.max(0, (quiz.totalQuestions || 0) - 1) });
    }
  }
};

import { 
  collection, 
  addDoc, 
  getDocs, 
  query, 
  where, 
  orderBy,
  doc,
  updateDoc,
  limit
} from 'firebase/firestore';
import { db } from '../core/firebase';
import { Submission } from '../core/types';

/**
 * submissionService - Exam Integrity & Results
 * Prevents multiple attempts and manages the state of active exams.
 */
export const submissionService = {
  /**
   * Check if user already has a submission for this quiz
   */
  async getSubmission(quizId: string, userId: string): Promise<Submission | null> {
    const q = query(
      collection(db, 'submissions'),
      where('quizId', '==', quizId),
      where('studentId', '==', userId),
      limit(1)
    );
    const snapshot = await getDocs(q);
    if (snapshot.empty) return null;
    const first = snapshot.docs[0];
    return { id: first.id, ...first.data() } as Submission;
  },

  /**
   * Create an initial submission record
   * Blocks if duplicate found.
   */
  async createSubmission(data: Omit<Submission, 'id'>): Promise<string> {
    // Duplicate Protection
    const existing = await this.getSubmission(data.quizId, data.studentId);
    if (existing) {
      throw new Error("You have already started or completed this examination.");
    }

    const docRef = await addDoc(collection(db, 'submissions'), {
      ...data,
      status: 'active',
      createdAt: Date.now()
    });
    return docRef.id;
  },

  /**
   * Autosave: Merge an answer into the submission map
   */
  async autosaveAnswer(submissionId: string, questionId: string, selectedIndex: number): Promise<void> {
    const docRef = doc(db, 'submissions', submissionId);
    // Use dot notation to update a specific key in the answers map field
    await updateDoc(docRef, {
      [`answers.${questionId}`]: selectedIndex
    });
  },

  /**
   * Final Submit: Close the examination and record score
   */
  async finalSubmit(submissionId: string, score: number): Promise<void> {
    const docRef = doc(db, 'submissions', submissionId);
    await updateDoc(docRef, {
      score,
      status: 'completed',
      completedAt: Date.now()
    });
  },

  async getStudentResults(studentId: string): Promise<Submission[]> {
    const q = query(
      collection(db, 'submissions'), 
      where('studentId', '==', studentId),
      orderBy('completedAt', 'desc')
    );
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
  },

  async getQuizResults(quizId: string): Promise<Submission[]> {
    const q = query(
      collection(db, 'submissions'), 
      where('quizId', '==', quizId),
      orderBy('score', 'desc')
    );
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
  }
};

