import React, { useEffect, useState } from 'react';
import { Navbar, Container, Card } from '../ui/Layout';
import { quizService } from '../services/quizService';
import { questionService } from '../services/questionService';
import { Quiz, Question } from '../core/types';
import { useAuth } from '../auth/AuthProvider';

const QuizManagement: React.FC = () => {
  const [quizzes, setQuizzes] = useState<Quiz[]>([]);
  const [showModal, setShowModal] = useState(false);
  const [activeQuiz, setActiveQuiz] = useState<Quiz | null>(null);
  const [questions, setQuestions] = useState<Question[]>([]);
  const { profile } = useAuth();

  // Form State
  const [title, setTitle] = useState('');
  const [desc, setDesc] = useState('');
  const [time, setTime] = useState(30);

  // Question Form
  const [qText, setQText] = useState('');
  const [options, setOptions] = useState(['', '', '', '']);
  const [correct, setCorrect] = useState(0);

  useEffect(() => {
    fetchQuizzes();
  }, []);

  const fetchQuizzes = async () => {
    const data = await quizService.getAllQuizzes();
    setQuizzes(data);
  };

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!profile) return;
    await quizService.createQuiz({ title, description: desc, timeLimit: time }, profile.uid);
    setShowModal(false);
    fetchQuizzes();
  };

  const openQuizBuilder = async (quiz: Quiz) => {
    setActiveQuiz(quiz);
    // Fix: Targeted questionService.getQuestionsByQuiz instead of non-existent quizService method
    const qs = await questionService.getQuestionsByQuiz(quiz.id);
    setQuestions(qs);
  };

  const handleAddQuestion = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!activeQuiz) return;
    // Fix: Targeted questionService.addQuestion instead of non-existent quizService method
    await questionService.addQuestion(activeQuiz.id, {
      text: qText,
      options,
      correctOptionIndex: correct
    });
    setQText('');
    setOptions(['', '', '', '']);
    // Fix: Targeted questionService.getQuestionsByQuiz instead of non-existent quizService method
    const qs = await questionService.getQuestionsByQuiz(activeQuiz.id);
    setQuestions(qs);
    fetchQuizzes();
  };

  const togglePublish = async (quiz: Quiz) => {
    await quizService.updateQuiz(quiz.id, { published: !quiz.published });
    fetchQuizzes();
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <Navbar />
      <Container>
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold text-slate-900">Quiz Management</h1>
          <button onClick={() => setShowModal(true)} className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-bold">New Quiz</button>
        </div>

        <div className="grid lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1 space-y-4">
            {quizzes.map(quiz => (
              <Card key={quiz.id} className={`p-4 cursor-pointer transition ${activeQuiz?.id === quiz.id ? 'ring-2 ring-indigo-500 bg-indigo-50' : 'hover:bg-white'}`} onClick={() => openQuizBuilder(quiz)}>
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-slate-900">{quiz.title}</h3>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full uppercase font-bold ${quiz.published ? 'bg-green-100 text-green-700' : 'bg-slate-200 text-slate-600'}`}>
                    {quiz.published ? 'Live' : 'Draft'}
                  </span>
                </div>
                <p className="text-xs text-slate-500 line-clamp-1">{quiz.description}</p>
                <div className="mt-4 flex items-center justify-between">
                   <div className="text-xs font-bold text-slate-400">
                     <i className="far fa-clock mr-1"></i> {quiz.timeLimit}m
                     <i className="fas fa-list ml-3 mr-1"></i> {quiz.totalQuestions} Questions
                   </div>
                   <button onClick={(e) => { e.stopPropagation(); togglePublish(quiz); }} className="text-indigo-600 text-xs font-bold">
                     {quiz.published ? 'Unpublish' : 'Publish'}
                   </button>
                </div>
              </Card>
            ))}
          </div>

          <div className="lg:col-span-2">
            {activeQuiz ? (
              <div className="space-y-6">
                <Card className="p-6">
                   <h2 className="text-xl font-bold mb-4">Add Question to "{activeQuiz.title}"</h2>
                   <form onSubmit={handleAddQuestion} className="space-y-4">
                      <textarea 
                        value={qText} 
                        onChange={e => setQText(e.target.value)} 
                        placeholder="Type question here..." 
                        className="w-full p-4 border rounded-xl outline-none focus:ring-2 focus:ring-indigo-500" 
                        required
                      />
                      <div className="grid grid-cols-2 gap-4">
                         {options.map((opt, i) => (
                           <div key={i} className="flex items-center space-x-2">
                             <input 
                               type="radio" 
                               name="correct" 
                               checked={correct === i} 
                               onChange={() => setCorrect(i)} 
                             />
                             <input 
                               type="text" 
                               value={opt} 
                               onChange={e => {
                                 const next = [...options];
                                 next[i] = e.target.value;
                                 setOptions(next);
                               }} 
                               placeholder={`Option ${i+1}`}
                               className="w-full p-2 border rounded-lg text-sm"
                               required
                             />
                           </div>
                         ))}
                      </div>
                      <button type="submit" className="w-full bg-slate-900 text-white py-3 rounded-xl font-bold">Save Question</button>
                   </form>
                </Card>

                <div className="space-y-4">
                   <h3 className="font-bold text-slate-900">Quiz Content ({questions.length})</h3>
                   {questions.map((q, idx) => (
                     <Card key={q.id} className="p-4 bg-white">
                        <p className="font-bold mb-3">{idx + 1}. {q.text}</p>
                        <div className="grid grid-cols-2 gap-2">
                          {q.options.map((opt, i) => (
                            <div key={i} className={`p-2 rounded-lg text-sm border ${i === q.correctOptionIndex ? 'bg-green-50 border-green-200 text-green-700 font-bold' : 'bg-slate-50 border-slate-100'}`}>
                              {opt}
                            </div>
                          ))}
                        </div>
                     </Card>
                   ))}
                </div>
              </div>
            ) : (
              <div className="h-64 flex flex-col items-center justify-center text-slate-400 border-2 border-dashed rounded-3xl">
                <i className="fas fa-edit text-4xl mb-4"></i>
                <p>Select a quiz to manage questions</p>
              </div>
            )}
          </div>
        </div>

        {showModal && (
          <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <Card className="max-w-md w-full p-8 relative">
              <button onClick={() => setShowModal(false)} className="absolute top-4 right-4 text-slate-400 hover:text-slate-900">
                <i className="fas fa-times"></i>
              </button>
              <h2 className="text-2xl font-bold mb-6">Create New Quiz</h2>
              <form onSubmit={handleCreate} className="space-y-4">
                <div>
                  <label className="block text-sm font-bold mb-1">Title</label>
                  <input type="text" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-3 border rounded-xl" required />
                </div>
                <div>
                  <label className="block text-sm font-bold mb-1">Description</label>
                  <textarea value={desc} onChange={e => setDesc(e.target.value)} className="w-full p-3 border rounded-xl" required />
                </div>
                <div>
                  <label className="block text-sm font-bold mb-1">Time Limit (Minutes)</label>
                  <input type="number" value={time} onChange={e => setTime(Number(e.target.value))} className="w-full p-3 border rounded-xl" required />
                </div>
                <button type="submit" className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold">Create Exam</button>
              </form>
            </Card>
          </div>
        )}
      </Container>
    </div>
  );
};

