import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Navbar, Container, Card } from '../ui/Layout';
import { submissionService } from '../services/submissionService';
import { quizService } from '../services/quizService';
import { Submission, Quiz } from '../core/types';

const Results: React.FC = () => {
  const { submissionId } = useParams<{ submissionId: string }>();
  const navigate = useNavigate();
  const [submission, setSubmission] = useState<Submission | null>(null);
  const [quiz, setQuiz] = useState<Quiz | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (submissionId) {
      loadData(submissionId);
    }
  }, [submissionId]);

  const loadData = async (sid: string) => {
    try {
      // Need a direct fetch by submission ID (not quizId+userId)
      // Since submissionService doesn't have getSubmissionById, we use getStudentResults and filter or add it to service.
      // For now, let's assume we can find it in student's history.
      const studentId = (await import('../core/firebase')).auth.currentUser?.uid;
      if (!studentId) return;

      const history = await submissionService.getStudentResults(studentId);
      const sub = history.find(h => h.id === sid);

      if (!sub) {
        navigate('/student');
        return;
      }

      const qz = await quizService.getQuiz(sub.quizId);
      setSubmission(sub);
      setQuiz(qz);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div className="h-screen flex items-center justify-center">Loading certificate...</div>;
  if (!submission) return <div className="p-12 text-center">Results not found.</div>;

  const percentage = Math.round((submission.score / submission.totalPossible) * 100);
  const isPassed = percentage >= 70;

  return (
    <div className="min-h-screen bg-slate-50">
      <Navbar />
      <Container>
        <div className="max-w-2xl mx-auto py-12">
          <Card className="relative overflow-hidden border-none shadow-2xl">
            <div className={`h-3 w-full ${isPassed ? 'bg-green-500' : 'bg-red-500'}`}></div>
            <div className="p-12 text-center">
              <div className={`w-24 h-24 mx-auto mb-6 rounded-full flex items-center justify-center text-4xl shadow-inner ${isPassed ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                <i className={`fas ${isPassed ? 'fa-award' : 'fa-exclamation-triangle'}`}></i>
              </div>

              <h1 className="text-4xl font-black text-slate-900 mb-2">{isPassed ? 'Examination Success' : 'Examination Attempted'}</h1>
              <p className="text-slate-500 font-medium mb-10">Official result record for {quiz?.title}</p>

              <div className="bg-slate-50 rounded-3xl p-8 mb-10 inline-block min-w-[300px] border border-slate-100">
                <p className="text-sm font-bold text-slate-400 uppercase tracking-[0.2em] mb-4">Official Score</p>
                <div className="flex items-center justify-center space-x-4">
                  <span className="text-7xl font-black text-slate-900">{percentage}%</span>
                  <div className="text-left border-l-2 border-slate-200 pl-4">
                    <p className="text-2xl font-bold text-indigo-600">{submission.score}</p>
                    <p className="text-xs font-bold text-slate-400 uppercase">Correct</p>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 text-left text-sm mb-12 max-w-sm mx-auto">
                <div className="p-4 bg-white rounded-xl border border-slate-100">
                   <p className="text-slate-400 font-bold uppercase text-[10px] mb-1">Student</p>
                   <p className="text-slate-900 font-bold">{submission.studentName}</p>
                </div>
                <div className="p-4 bg-white rounded-xl border border-slate-100">
                   <p className="text-slate-400 font-bold uppercase text-[10px] mb-1">Date</p>
                   <p className="text-slate-900 font-bold">{new Date(submission.completedAt).toLocaleDateString()}</p>
                </div>
              </div>

              <div className="flex flex-col space-y-4">
                <Link 
                  to="/student" 
                  className="bg-indigo-600 text-white py-4 rounded-xl font-bold hover:bg-indigo-700 transition shadow-lg shadow-indigo-100"
                >
                  Return to Dashboard
                </Link>
                <button 
                  onClick={() => window.print()}
                  className="text-slate-400 text-xs font-bold hover:text-slate-600 transition"
                >
                  <i className="fas fa-print mr-2"></i> Print Official Record
                </button>
              </div>
            </div>
          </Card>
        </div>
      </Container>
    </div>
  );
};

