import { ref, uploadBytes, getDownloadURL, listAll, deleteObject } from "firebase/storage";
import { storage } from "../core/firebase";

/**
 * storageService - Exam Resource Management
 * Handles binary assets like PDFs and images for quizzes.
 */
export const storageService = {
  /**
   * Upload a file to a specific quiz directory
   */
  async uploadFile(quizId: string, file: File): Promise<string> {
    const fileRef = ref(storage, `exam_files/${quizId}/${Date.now()}_${file.name}`);
    const snapshot = await uploadBytes(fileRef, file);
    return await getDownloadURL(snapshot.ref);
  },

  /**
   * List all files associated with a specific quiz
   */
  async getFilesByQuiz(quizId: string) {
    const listRef = ref(storage, `exam_files/${quizId}`);
    const res = await listAll(listRef);

    const filePromises = res.items.map(async (item) => {
      const url = await getDownloadURL(item);
      return {
        name: item.name,
        fullPath: item.fullPath,
        url
      };
    });

    return Promise.all(filePromises);
  },

  /**
   * Remove a resource
   */
  async deleteFile(fullPath: string): Promise<void> {
    const fileRef = ref(storage, fullPath);
    await deleteObject(fileRef);
  }
};

import { doc, getDoc, updateDoc, collection, getDocs, query, orderBy } from "firebase/firestore";
import { db } from "../core/firebase";
import { UserProfile } from "../core/types";

/**
 * userService - Identity & Role Management
 * Pure Firestore operations for user data.
 */
export const userService = {
  /**
   * Fetch a user profile from Firestore
   */
  async getUserProfile(uid: string): Promise<UserProfile | null> {
    const docRef = doc(db, "users", uid);
    const docSnap = await getDoc(docRef);
    return docSnap.exists() ? (docSnap.data() as UserProfile) : null;
  },

  /**
   * Update a user's profile information
   */
  async updateUserProfile(uid: string, data: Partial<UserProfile>): Promise<void> {
    const docRef = doc(db, "users", uid);
    await updateDoc(docRef, data);
  },

  /**
   * Admin: List all registered users
   */
  async getAllUsers(): Promise<UserProfile[]> {
    const q = query(collection(db, "users"), orderBy("createdAt", "desc"));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ ...doc.data() } as UserProfile));
  }
};

import { 
  collection, 
  addDoc, 
  getDocs, 
  query, 
  where, 
  orderBy,
  doc,
  updateDoc,
  limit
} from 'firebase/firestore';
import { db } from '../core/firebase';
import { Submission } from '../core/types';

/**
 * submissionService - Exam Integrity & Results
 * Prevents multiple attempts and manages the state of active exams.
 */
export const submissionService = {
  /**
   * Check if user already has a submission for this quiz
   */
  async getSubmission(quizId: string, userId: string): Promise<Submission | null> {
    const q = query(
      collection(db, 'submissions'),
      where('quizId', '==', quizId),
      where('studentId', '==', userId),
      limit(1)
    );
    const snapshot = await getDocs(q);
    if (snapshot.empty) return null;
    const first = snapshot.docs[0];
    return { id: first.id, ...first.data() } as Submission;
  },

  /**
   * Create an initial submission record
   */
  async createSubmission(data: Omit<Submission, 'id'>): Promise<string> {
    const existing = await this.getSubmission(data.quizId, data.studentId);
    if (existing) {
      throw new Error("You have already started or completed this examination.");
    }

    const docRef = await addDoc(collection(db, 'submissions'), {
      ...data,
      status: 'active',
      createdAt: Date.now()
    });
    return docRef.id;
  },

  /**
   * Final Full Submit
   */
  async submitExam(data: Omit<Submission, 'id'>): Promise<string> {
    const existing = await this.getSubmission(data.quizId, data.studentId);
    if (existing) {
      throw new Error("You have already submitted this examination.");
    }

    const docRef = await addDoc(collection(db, 'submissions'), {
      ...data,
      status: 'completed',
      createdAt: Date.now()
    });
    return docRef.id;
  },

  /**
   * Autosave
   */
  async autosaveAnswer(submissionId: string, questionId: string, selectedIndex: number): Promise<void> {
    const docRef = doc(db, 'submissions', submissionId);
    await updateDoc(docRef, {
      [`answers.${questionId}`]: selectedIndex
    });
  },

  /**
   * Final Submit
   */
  async finalSubmit(submissionId: string, score: number): Promise<void> {
    const docRef = doc(db, 'submissions', submissionId);
    await updateDoc(docRef, {
      score,
      status: 'completed',
      completedAt: Date.now()
    });
  },

  /**
   * Admin/Student: Get all submissions for a student
   */
  async getStudentResults(studentId: string): Promise<Submission[]> {
    const q = query(
      collection(db, 'submissions'), 
      where('studentId', '==', studentId),
      orderBy('createdAt', 'desc')
    );
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
  },

  /**
   * Admin: Get all submissions for a quiz
   */
  async getQuizResults(quizId: string): Promise<Submission[]> {
    const q = query(
      collection(db, 'submissions'), 
      where('quizId', '==', quizId),
      orderBy('score', 'desc')
    );
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
  },

  /**
   * Admin: Get all submissions globally
   */
  async getAllSubmissions(): Promise<Submission[]> {
    const q = query(collection(db, 'submissions'), orderBy('createdAt', 'desc'));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
  }
};

import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Navbar, Container, Card } from '../ui/Layout';
import { questionService } from '../services/questionService';
import { quizService } from '../services/quizService';
import { Quiz, Question } from '../core/types';

const QuestionBuilder: React.FC = () => {
  const { quizId } = useParams<{ quizId: string }>();
  const [quiz, setQuiz] = useState<Quiz | null>(null);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [loading, setLoading] = useState(true);

  // Form
  const [text, setText] = useState('');
  const [options, setOptions] = useState(['', '', '', '']);
  const [correct, setCorrect] = useState(0);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (quizId) loadData(quizId);
  }, [quizId]);

  const loadData = async (id: string) => {
    try {
      const [qz, qs] = await Promise.all([
        quizService.getQuiz(id),
        questionService.getQuestionsByQuiz(id)
      ]);
      setQuiz(qz);
      setQuestions(qs);
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!quizId || saving) return;
    setSaving(true);
    try {
      await questionService.addQuestion(quizId, {
        text,
        options,
        correctOptionIndex: correct
      });
      setText('');
      setOptions(['', '', '', '']);
      setCorrect(0);
      const qs = await questionService.getQuestionsByQuiz(quizId);
      setQuestions(qs);
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className="p-12 text-center">Loading Question Builder...</div>;

  return (
    <div className="min-h-screen bg-slate-50">
      <Navbar />
      <Container>
        <div className="mb-8 flex items-center justify-between">
          <div>
            <Link to="/admin/quizzes" className="text-indigo-600 text-sm font-bold flex items-center mb-2">
              <i className="fas fa-arrow-left mr-2"></i> Back to Quizzes
            </Link>
            <h1 className="text-3xl font-bold text-slate-900">Building: {quiz?.title}</h1>
          </div>
          <div className="bg-white px-4 py-2 rounded-xl border border-slate-200 text-sm font-bold text-slate-500">
             {questions.length} Questions Created
          </div>
        </div>

        <div className="grid lg:grid-cols-2 gap-8">
           <Card className="p-8 sticky top-24 h-fit">
              <h2 className="text-xl font-bold mb-6">New Question</h2>
              <form onSubmit={handleSave} className="space-y-6">
                 <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Question Text</label>
                    <textarea 
                      value={text}
                      onChange={e => setText(e.target.value)}
                      className="w-full p-4 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition min-h-[120px]"
                      placeholder="e.g. What is the complexity of binary search?"
                      required
                    />
                 </div>
                 <div className="space-y-3">
                    <label className="block text-xs font-bold text-slate-400 uppercase">Multiple Choice Options</label>
                    {options.map((opt, i) => (
                      <div key={i} className="flex items-center space-x-3">
                        <input 
                          type="radio" 
                          name="correct" 
                          checked={correct === i}
                          onChange={() => setCorrect(i)}
                          className="w-4 h-4 text-indigo-600"
                        />
                        <input 
                          type="text" 
                          value={opt}
                          onChange={e => {
                            const n = [...options];
                            n[i] = e.target.value;
                            setOptions(n);
                          }}
                          placeholder={`Option ${i+1}`}
                          className="flex-1 p-3 border rounded-lg text-sm"
                          required
                        />
                      </div>
                    ))}
                 </div>
                 <button 
                  type="submit" 
                  disabled={saving}
                  className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold hover:bg-indigo-600 transition disabled:opacity-50"
                 >
                   {saving ? 'Saving...' : 'Add to Examination'}
                 </button>
              </form>
           </Card>

           <div className="space-y-6">
              <h2 className="text-xl font-bold text-slate-900">Question Sequence</h2>
              {questions.length === 0 ? (
                <div className="p-20 text-center border-2 border-dashed rounded-3xl text-slate-400">
                  <p>No questions added to this quiz yet.</p>
                </div>
              ) : (
                questions.map((q, idx) => (
                  <Card key={q.id} className="p-6">
                    <div className="flex justify-between items-start mb-4">
                      <span className="bg-slate-100 text-slate-600 text-[10px] font-black px-2 py-0.5 rounded uppercase">Q{idx + 1}</span>
                      <button 
                        onClick={async () => {
                          if(confirm("Delete question?")) {
                            await questionService.deleteQuestion(q.id, quizId!);
                            loadData(quizId!);
                          }
                        }}
                        className="text-slate-300 hover:text-red-600 transition"
                      >
                        <i className="fas fa-trash-alt"></i>
                      </button>
                    </div>
                    <p className="font-bold text-slate-900 mb-6">{q.text}</p>
                    <div className="grid grid-cols-2 gap-3">
                      {q.options.map((opt, i) => (
                        <div key={i} className={`p-3 rounded-xl border text-sm ${i === q.correctOptionIndex ? 'bg-green-50 border-green-200 text-green-700 font-bold' : 'bg-slate-50 border-slate-100 text-slate-500'}`}>
                          {opt}
                        </div>
                      ))}
                    </div>
                  </Card>
                ))
              )}
           </div>
        </div>
      </Container>
    </div>
  );
};

export default QuestionBuilder;

import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Navbar, Container, Card } from '../ui/Layout';
import { storageService } from '../services/storageService';
import { quizService } from '../services/quizService';
import { Quiz } from '../core/types';

const FileExplorer: React.FC = () => {
  const { quizId } = useParams<{ quizId: string }>();
  const [quiz, setQuiz] = useState<Quiz | null>(null);
  const [files, setFiles] = useState<any[]>([]);
  const [uploading, setUploading] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (quizId) loadData(quizId);
  }, [quizId]);

  const loadData = async (id: string) => {
    try {
      const [qz, fls] = await Promise.all([
        quizService.getQuiz(id),
        storageService.getFilesByQuiz(id)
      ]);
      setQuiz(qz);
      setFiles(fls);
    } finally {
      setLoading(false);
    }
  };

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !quizId) return;

    setUploading(true);
    try {
      await storageService.uploadFile(quizId, file);
      await loadData(quizId);
    } finally {
      setUploading(false);
    }
  };

  const handleDelete = async (path: string) => {
    if (!confirm("Remove this resource permanently?")) return;
    await storageService.deleteFile(path);
    await loadData(quizId!);
  };

  if (loading) return <div className="p-12 text-center">Opening Vault...</div>;

  return (
    <div className="min-h-screen bg-slate-50">
      <Navbar />
      <Container>
        <div className="mb-8">
           <Link to="/admin/quizzes" className="text-indigo-600 text-sm font-bold flex items-center mb-2">
            <i className="fas fa-arrow-left mr-2"></i> Back to Quizzes
          </Link>
          <h1 className="text-3xl font-bold text-slate-900">Resource Vault: {quiz?.title}</h1>
        </div>

        <div className="grid lg:grid-cols-4 gap-8">
           <Card className="lg:col-span-1 p-6 h-fit bg-slate-900 text-white">
              <h3 className="font-bold mb-4">Add Resource</h3>
              <p className="text-xs text-slate-400 mb-6">Upload diagrams, reference PDFs, or case study images for this exam.</p>

              <label className="block w-full text-center py-4 bg-indigo-600 rounded-xl font-bold cursor-pointer hover:bg-indigo-700 transition">
                 {uploading ? <i className="fas fa-circle-notch animate-spin"></i> : 'Select File'}
                 <input type="file" className="hidden" onChange={handleUpload} disabled={uploading} />
              </label>
           </Card>

           <Card className="lg:col-span-3 p-8">
              <h3 className="text-xl font-bold text-slate-900 mb-8">Exam Assets ({files.length})</h3>
              {files.length === 0 ? (
                <div className="text-center py-20 text-slate-400">
                  <i className="fas fa-cloud-upload-alt text-5xl mb-4 opacity-20"></i>
                  <p>No files uploaded for this examination module.</p>
                </div>
              ) : (
                <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-6">
                   {files.map((f, i) => (
                     <div key={i} className="group relative bg-slate-50 rounded-2xl border border-slate-100 overflow-hidden hover:shadow-lg transition">
                        <div className="h-32 bg-slate-200 flex items-center justify-center overflow-hidden">
                           {f.name.match(/\.(jpg|jpeg|png|gif)$/i) ? (
                             <img src={f.url} className="w-full h-full object-cover" alt="" />
                           ) : (
                             <i className="fas fa-file-pdf text-4xl text-red-400"></i>
                           )}
                        </div>
                        <div className="p-4">
                           <p className="text-xs font-bold text-slate-900 truncate mb-1" title={f.name}>{f.name}</p>
                           <div className="flex items-center justify-between">
                              <a href={f.url} target="_blank" rel="noreferrer" className="text-[10px] text-indigo-600 font-bold uppercase">View Link</a>
                              <button onClick={() => handleDelete(f.fullPath)} className="text-slate-300 hover:text-red-600 transition">
                                <i className="fas fa-trash-alt text-xs"></i>
                              </button>
                           </div>
                        </div>
                     </div>
                   ))}
                </div>
              )}
           </Card>
        </div>
      </Container>
    </div>
  );
};

export default FileExplorer;

