const Results: React.FC = () => {
  const { submissionId } = useParams<{ submissionId: string }>();
  const navigate = useNavigate();
  const [submission, setSubmission] = useState<Submission | null>(null);
  const [quiz, setQuiz] = useState<Quiz | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (submissionId) {
      loadData(submissionId);
    }
  }, [submissionId]);

  const loadData = async (sid: string) => {
    try {
      // Need a direct fetch by submission ID (not quizId+userId)
      // Since submissionService doesn't have getSubmissionById, we use getStudentResults and filter or add it to service.
      // For now, let's assume we can find it in student's history.
      const studentId = (await import('../core/firebase')).auth.currentUser?.uid;
      if (!studentId) return;

      const history = await submissionService.getStudentResults(studentId);
      const sub = history.find(h => h.id === sid);

      if (!sub) {
        navigate('/student');
        return;
      }

      const qz = await quizService.getQuiz(sub.quizId);
      setSubmission(sub);
      setQuiz(qz);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div className="h-screen flex items-center justify-center">Loading certificate...</div>;
  if (!submission) return <div className="p-12 text-center">Results not found.</div>;

  const percentage = Math.round((submission.score / submission.totalPossible) * 100);
