/**
 * Translate Firebase Auth errors into user-friendly messages.
 */
const translateError = (code: string): string => {
  switch (code) {
    case "auth/user-not-found":
    case "auth/wrong-password":
    case "auth/invalid-credential":
      return "Password or Email Incorrect";
    case "auth/email-already-in-use":
      return "User already exists. Sign in?";
    case "auth/weak-password":
      return "Password is too weak.";
    case "auth/invalid-email":
      return "Invalid email address.";
    default:
      return "An unexpected error occurred. Please try again.";
  }
};

// System Owner Configuration
const SYSTEM_OWNER_EMAIL = "nelymsjnr@gmail.com";

export const authService = {
  /**
   * Log in an existing user
   */
  async login(email: string, pass: string) {
    try {
      const credential = await signInWithEmailAndPassword(auth, email, pass);
      return credential.user;
    } catch (error: any) {
      throw new Error(translateError(error.code));
    }
  },

  /**
   * Sign up a new user
   * If the email matches the system owner, they are granted admin privileges immediately.
   */
  async signup(email: string, pass: string, name: string) {
    try {
      const credential = await createUserWithEmailAndPassword(auth, email, pass);
      const user = credential.user;

      // Update Auth display name
      await updateProfile(user, { displayName: name });

      // Determine initial role
      const initialRole: UserRole = email.toLowerCase() === SYSTEM_OWNER_EMAIL.toLowerCase() ? "admin" : "student";

      // Create Firestore profile document
      await setDoc(doc(db, "users", user.uid), {
        uid: user.uid,
        displayName: name,
        email: email.toLowerCase(),
        role: initialRole,
        createdAt: Date.now(),
      });

      return user;
    } catch (error: any) {
      throw new Error(translateError(error.code));
    }
  },
};

rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Helper: Is the user authenticated?
    function isSignedIn() {
      return request.auth != null;
    }

    // Helper: Does the user have the Admin role?
    function isAdmin() {
      return isSignedIn() && 
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin';
    }

    // Helper: Is the user the owner of the document?
    function isOwner(userId) {
      return isSignedIn() && request.auth.uid == userId;
    }

    // Users Collection
    match /users/{userId} {
      allow create: if isSignedIn();
      allow read: if isOwner(userId) || isAdmin();
      allow update: if isAdmin(); // Only admins can change roles
      allow list: if isAdmin();
    }

    // Quizzes Collection
    match /quizzes/{quizId} {
      allow read: if isSignedIn() && (resource.data.published == true || isAdmin());
      allow write: if isAdmin();
    }

    // Questions Collection
    match /questions/{questionId} {
      // Questions are readable if the user is an admin or if the quiz is published
      // Note: In a production environment, you'd join with the quiz document
      allow read: if isSignedIn(); 
      allow write: if isAdmin();
    }

    // Submissions Collection
    match /submissions/{submissionId} {
      allow create: if isSignedIn();
      allow read: if isAdmin() || (isSignedIn() && resource.data.studentId == request.auth.uid);
      allow update: if isAdmin() || (isSignedIn() && resource.data.studentId == request.auth.uid && resource.data.status == 'active');
      allow list: if isAdmin() || (isSignedIn() && request.query.limit <= 100); 
    }
  }
}

