service cloud.firestore {
  match /databases/{database}/documents {

    // Helper: Is the user authenticated?
    function isSignedIn() {
      return request.auth != null;
    }

    // Helper: Does the user have the Admin role?
    function isAdmin() {
      return isSignedIn() && 
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin';
    }

    // Helper: Is the user the owner of the document?
    function isOwner(userId) {
      return isSignedIn() && request.auth.uid == userId;
    }

    // Users Collection
    match /users/{userId} {
      allow read: if isOwner(userId) || isAdmin();
      allow create: if isSignedIn();
      allow update: if isAdmin() || (isOwner(userId) && request.resource.data.role == resource.data.role);
    }

    // Explicit rule for collection listings
    match /users {
      allow list: if isAdmin();
    }

    // Quizzes Collection
    match /quizzes/{quizId} {
      allow read: if isSignedIn() && (resource.data.published == true || isAdmin());
      allow write: if isAdmin();
    }

    // Questions Collection
    match /questions/{questionId} {
      allow read: if isSignedIn(); 
      allow write: if isAdmin();
    }

    // Submissions Collection
    match /submissions/{submissionId} {
      allow create: if isSignedIn();
      allow read: if isAdmin() || (isSignedIn() && resource.data.studentId == request.auth.uid);
      allow update: if isAdmin() || (isSignedIn() && resource.data.studentId == request.auth.uid && resource.data.status == 'active');

      // Allow list queries if admin or if filtered by studentId (handled in client)
      allow list: if isAdmin() || (isSignedIn() && request.query.limit <= 100); 
    }
  }
}

