import React, { createContext, useContext, useEffect, useState } from "react";
import { auth, db } from "../core/firebase";
import { onAuthStateChanged, User } from "firebase/auth";
import { doc, onSnapshot, getDoc, setDoc } from "firebase/firestore";
import { UserRole, UserProfile } from "../core/types";

interface AuthContextType {
  user: User | null;
  profile: UserProfile | null;
  role: UserRole | null;
  loading: boolean;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

// System Owner Configuration for role-based auto-provisioning
const SYSTEM_OWNER_EMAIL = "nelymsjnr@gmail.com";

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let unsubscribeProfile: (() => void) | null = null;

    // Listen for authentication state changes
    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      // Clear existing profile listener if user changes or signs out
      if (unsubscribeProfile) {
        unsubscribeProfile();
        unsubscribeProfile = null;
      }

      setUser(firebaseUser);

      if (firebaseUser) {
        setLoading(true);
        const docRef = doc(db, "users", firebaseUser.uid);

        try {
          // 1. Ensure profile exists - Critical for Firestore Security Rules
          const docSnap = await getDoc(docRef);

          if (!docSnap.exists()) {
            // New account or missing profile doc - Provision now
            const initialRole: UserRole = firebaseUser.email?.toLowerCase() === SYSTEM_OWNER_EMAIL.toLowerCase() 
              ? "admin" 
              : "student";

            await setDoc(docRef, {
              uid: firebaseUser.uid,
              displayName: firebaseUser.displayName || "Academy Member",
              email: firebaseUser.email,
              role: initialRole,
              createdAt: Date.now(),
            });
            // Note: The onSnapshot below will trigger once the write is detected locally
          }

          // 2. Setup real-time listener to keep state in sync
          unsubscribeProfile = onSnapshot(docRef, (snap) => {
            if (snap.exists()) {
              const data = snap.data() as UserProfile;
              setProfile(data);
              setRole(data.role);
              setLoading(false);
            } else {
              setProfile(null);
              setRole(null);
              setLoading(false);
            }
          }, (error) => {
            console.error("Profile sync error:", error);
            setLoading(false);
          });
        } catch (error) {
          console.error("Profile reconciliation failure:", error);
          setLoading(false);
        }
      } else {
        setProfile(null);
        setRole(null);
        setLoading(false);
      }
    });

    // Cleanup listener on unmount
    return () => {
      unsubscribeAuth();
      if (unsubscribeProfile) unsubscribeProfile();
    };
  }, []);

  const logout = async () => {
    await auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, profile, role, loading, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};

