service cloud.firestore {
  match /databases/{database}/documents {

    // Helper: Is the user authenticated?
    function isSignedIn() {
      return request.auth != null;
    }

    // Helper: Is the user an administrator?
    // Uses the owner email as a hard-coded bypass or checks the 'role' field in the user document.
    // Short-circuits on email to avoid unnecessary document reads.
    function isAdmin() {
      return isSignedIn() && (
        request.auth.token.email.matches('(?i)nelymsjnr@gmail.com') ||
        (exists(/databases/$(database)/documents/users/$(request.auth.uid)) && 
         get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin')
      );
    }

    // Users: Admin can list/read all. Students can read only their own.
    match /users {
      allow list: if isAdmin();
      match /{userId} {
        allow read: if isSignedIn() && (request.auth.uid == userId || isAdmin());
        allow create: if isSignedIn();
        allow update: if isAdmin() || (isSignedIn() && request.auth.uid == userId && request.resource.data.role == resource.data.role);
      }
    }

    // Quizzes: Admin can list/read/write all. Students can list/read ONLY published ones.
    match /quizzes {
      allow list: if isAdmin();
      match /{quizId} {
        allow read: if isSignedIn() && (isAdmin() || resource.data.published == true);
        // Explicit list rule for students: requires where('published', '==', true) in query
        allow list: if isSignedIn() && resource.data.published == true;
        allow write: if isAdmin();
      }
    }

    // Questions: Content for exams.
    match /questions {
      allow list: if isSignedIn();
      match /{questionId} {
        allow read: if isSignedIn();
        allow write: if isAdmin();
      }
    }

    // Submissions: Admin can list/read all. Students can list/read ONLY their own.
    match /submissions {
      allow list: if isAdmin();
      match /{submissionId} {
        allow create: if isSignedIn();
        allow read: if isSignedIn() && (isAdmin() || resource.data.studentId == request.auth.uid);
        // Explicit list rule for students: requires where('studentId', '==', uid) in query
        allow list: if isSignedIn() && resource.data.studentId == request.auth.uid;
        allow update: if isAdmin() || (isSignedIn() && request.auth.uid == userId && resource.data.status == 'active');
      }
    }
  }
}

