service cloud.firestore {
  match /databases/{database}/documents {

    // Helper: Is the user authenticated?
    function isSignedIn() {
      return request.auth != null;
    }

    // Helper: Is the user an administrator?
    // Tier 1: System Owner (Hardcoded UID & Email for absolute reliability)
    // Tier 2: Role-based check in the 'users' collection
    function isAdmin() {
      return isSignedIn() && (
        request.auth.uid == 'BWpCkZXfwzLxGCjozyEnScG8yS53' || 
        (request.auth.token.email != null && request.auth.token.email.lower() == 'nelymsjnr@gmail.com') ||
        (exists(/databases/$(database)/documents/users/$(request.auth.uid)) && 
         get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin')
      );
    }

    // Users Collection
    match /users {
      // Admin can list all; Students cannot list the collection.
      allow list: if isAdmin();
      match /{userId} {
        allow read: if isSignedIn() && (request.auth.uid == userId || isAdmin());
        allow create: if isSignedIn();
        allow update: if isAdmin() || (isSignedIn() && request.auth.uid == userId && request.resource.data.role == resource.data.role);
      }
    }

    // Quizzes Collection
    match /quizzes {
      // Admin can list all. Students can list with a limit (implied they only see published via query)
      allow list: if isSignedIn() && (isAdmin() || request.query.limit <= 100);
      match /{quizId} {
        allow read: if isSignedIn() && (isAdmin() || resource.data.published == true);
        allow write: if isAdmin();
      }
    }

    // Questions Collection
    match /questions {
      allow list: if isSignedIn();
      match /{questionId} {
        allow read: if isSignedIn();
        allow write: if isAdmin();
      }
    }

    // Submissions Collection
    match /submissions {
      // Admin can list all.
      allow list: if isSignedIn() && (isAdmin() || (request.query.limit <= 100 && request.query.offset == 0));
      match /{submissionId} {
        allow create: if isSignedIn();
        allow read: if isSignedIn() && (isAdmin() || resource.data.studentId == request.auth.uid);
        allow update: if isAdmin() || (isSignedIn() && resource.data.studentId == request.auth.uid && resource.data.status == 'active');
      }
    }
  }
}

