  const [studentCount, setStudentCount] = useState(0);
  const [subCount, setSubCount] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const isSystemOwner = user?.email?.toLowerCase() === 'nelymsjnr@gmail.com' || user?.uid === 'BWpCkZXfwzLxGCjozyEnScG8yS53';

  const fetchStats = useCallback(async (retryCount = 0) => {
    setLoading(true);
    setError(null);
    try {
      // Parallel execution to pinpoint failures
      const results = await Promise.allSettled([
        quizService.getAllQuizzes(),
        userService.getAllUsers(),
        submissionService.getAllSubmissions()
      ]);

      const [qRes, uRes, sRes] = results;

      if (qRes.status === 'fulfilled') {
        setQuizzes(qRes.value);
      } else {
        console.warn("Quiz Sync Issue:", qRes.reason);
      }

      if (uRes.status === 'fulfilled') {
        setStudentCount(uRes.value.filter(u => u.role === 'student').length);
      } else {
        console.warn("User Sync Issue:", uRes.reason);
      }

      if (sRes.status === 'fulfilled') {
        setSubCount(sRes.value.length);
      } else {
        console.warn("Submission Sync Issue:", sRes.reason);
      }

      // If everything rejected, it's a rule/permission lockout
      if (qRes.status === 'rejected' && uRes.status === 'rejected' && sRes.status === 'rejected') {
        if (retryCount < 1) {
          // Automatic retry once after 1.5s to allow rules engine to sync
          setTimeout(() => fetchStats(retryCount + 1), 1500);
        } else {
          setError("Access Restriction: Your administrative profile has not been fully verified by the secure vault. Please ensure your account has been assigned the 'admin' role.");
        }
      }

    } catch (err: any) {
      console.error("Critical Dashboard Error:", err);
      setError("An unexpected error occurred during database synchronization.");
