            <i className="fas fa-shield-virus mr-3 text-lg"></i>
            <div className="flex-1">
              <p className="font-bold">Database Verification Pending</p>
              <p className="opacity-80">{error}</p>
            </div>
            <button 
              onClick={() => fetchStats()} 
              className="ml-4 bg-white border border-red-200 px-4 py-2 rounded-lg transition text-xs font-black uppercase tracking-widest hover:bg-red-50"
            >
              Retry Sync
            </button>
          </div>
        )}

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          {stats.map((stat, i) => (
