        userService.getAllUsers(),
        submissionService.getAllSubmissions()
      ]);

      const [qRes, uRes, sRes] = results;

      // Map results or log warnings
      if (qRes.status === 'fulfilled') setQuizzes(qRes.value);
      if (uRes.status === 'fulfilled') setStudentCount(uRes.value.filter(u => u.role === 'student').length);
      if (sRes.status === 'fulfilled') setSubCount(sRes.value.length);

      // Analyze failures
      const failures = results.filter(r => r.status === 'rejected');

      if (failures.length > 0) {
        console.warn(`Sync partial failure (${failures.length}/3). Retrying...`, failures.map(f => (f as any).reason));

        if (retryCount < 2) {
          // Retry with increasing delay (1.5s, 3s)
          setTimeout(() => fetchStats(retryCount + 1), 1500 * (retryCount + 1));
        } else {
          setError("The high-security vault is taking longer than usual to verify your administrative tokens. Please refresh the page if this persists.");
        }
      } else {
        setError(null);
      }

    } catch (err: any) {
      console.error("Dashboard Exception:", err);
      setError("An internal error occurred during data synchronization.");
    } finally {
      setLoading(false);
    }
  }, [quizService, userService, submissionService]);

  useEffect(() => {
    // Wait for auth to settle
    if (!authLoading) {
      if (role === 'admin' || isSystemOwner) {
        fetchStats();
