import React, { createContext, useContext, useEffect, useState } from "react";
import { auth, db } from "../core/firebase";
import { onAuthStateChanged, User } from "firebase/auth";
import { doc, onSnapshot, getDoc, setDoc } from "firebase/firestore";
import { UserRole, UserProfile } from "../core/types";

interface AuthContextType {
  user: User | null;
  profile: UserProfile | null;
  role: UserRole | null;
  loading: boolean;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

// System Owner Configuration
const SYSTEM_OWNER_EMAIL = "nelymsjnr@gmail.com";
const SYSTEM_OWNER_UID = "BWpCkZXfwzLxGCjozyEnScG8yS53";

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [role, setRole] = useState<UserRole | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let unsubscribeProfile: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      if (unsubscribeProfile) {
        unsubscribeProfile();
        unsubscribeProfile = null;
      }

      setUser(firebaseUser);

      if (firebaseUser) {
        setLoading(true);
        const docRef = doc(db, "users", firebaseUser.uid);

        try {
          const docSnap = await getDoc(docRef);

          // Force Admin role for System Owner regardless of document state
          const isSystemOwner = firebaseUser.uid === SYSTEM_OWNER_UID || 
                               firebaseUser.email?.toLowerCase() === SYSTEM_OWNER_EMAIL;

          if (!docSnap.exists()) {
            const initialRole: UserRole = isSystemOwner ? "admin" : "student";

            await setDoc(docRef, {
              uid: firebaseUser.uid,
              displayName: firebaseUser.displayName || "Academy Member",
              email: firebaseUser.email?.toLowerCase() || "",
              role: initialRole,
              createdAt: Date.now(),
            });
          }

          // Real-time listener
          unsubscribeProfile = onSnapshot(docRef, (snap) => {
            if (snap.exists()) {
              const data = snap.data() as UserProfile;
              setProfile(data);
              // Owner override again to be absolutely sure in-app
              setRole(isSystemOwner ? "admin" : data.role);
              setLoading(false);
            } else {
              setProfile(null);
              setRole(isSystemOwner ? "admin" : null);
              setLoading(false);
            }
          }, (error) => {
            console.error("Profile sync error:", error);
            // If listener fails due to permission but we know they are owner, force admin
            if (isSystemOwner) {
              setRole("admin");
            }
            setLoading(false);
          });
        } catch (error) {
          console.error("Auth initialization failure:", error);
          if (isSystemOwner) setRole("admin");
          setLoading(false);
        }
      } else {
        setProfile(null);
        setRole(null);
        setLoading(false);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubscribeProfile) unsubscribeProfile();
    };
  }, []);

  const logout = async () => {
    await auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, profile, role, loading, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};

