service cloud.firestore {
  match /databases/{database}/documents {

    // ==========================================
    // GLOBAL HELPERS
    // ==========================================

    function isSignedIn() {
      return request.auth != null;
    }

    // Root-level authority for the System Owner (Developer/Admin)
    function isSystemOwner() {
      return isSignedIn() && (
        request.auth.uid == 'BWpCkZXfwzLxGCjozyEnScG8yS53' || 
        (request.auth.token.email != null && request.auth.token.email.lower() == 'nelymsjnr@gmail.com')
      );
    }

    // Role verification for other administrators
    function isAdmin() {
      return isSystemOwner() || (
        isSignedIn() && 
        exists(/databases/$(database)/documents/users/$(request.auth.uid)) && 
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin'
      );
    }

    // ==========================================
    // COLLECTION RULES
    // ==========================================

    // 1. Users Collection: Identity & Profiles
    match /users/{userId} {
      // Allow reading: Own profile or any profile if Admin
      allow read: if isSignedIn() && (request.auth.uid == userId || isAdmin());

      // Allow creation: Any signed-in user (usually on first signup)
      allow create: if isSignedIn() && request.auth.uid == userId;

      // Allow updates: 
      // - Admins can change everything
      // - Users can change their own displayName but NOT their role or core identifiers
      allow update: if isAdmin() || (
        isSignedIn() && 
        request.auth.uid == userId && 
        request.resource.data.role == resource.data.role &&
        request.resource.data.uid == resource.data.uid &&
        request.resource.data.email == resource.data.email
      );

      // List access: Restricted to Admins to protect privacy
      allow list: if isAdmin();
    }

    // 2. Quizzes Collection: Examination Metadata
    match /quizzes/{quizId} {
      // Allow reading: Admin can see all, Students only see Published
      allow read: if isSignedIn() && (isAdmin() || resource.data.published == true);

      // Allow write: Strictly Admin territory
      allow write: if isAdmin();

      // Listing: Admins see all, Students see Published (handled via query filters in app)
      allow list: if isSignedIn() && (isAdmin() || (request.query.limit != null && request.query.limit <= 500));
    }

    // 3. Questions Collection: Quiz Content
    match /questions/{questionId} {
      // Allow reading: Any signed-in user (necessary for taking exams)
      // Barrier is usually knowing the Question ID via a valid Quiz
      allow read: if isSignedIn();

      // Allow write: Strictly Admin territory
      allow write: if isAdmin();

      allow list: if isSignedIn();
    }

    // 4. Submissions Collection: Results & Proctoring
    match /submissions/{submissionId} {
      // Allow creation: Students creating their own initial attempt
      allow create: if isSignedIn() && request.resource.data.studentId == request.auth.uid;

      // Allow reading: Students seeing own result or Admin seeing all
      allow read: if isSignedIn() && (request.auth.uid == resource.data.studentId || isAdmin());

      // Allow update: 
      // - Admins can update anything (grading/comments)
      // - Students can update answers only while the session is 'active'
      // - Students cannot change the score once 'completed' or change the studentId
      allow update: if isAdmin() || (
        isSignedIn() && 
        request.auth.uid == resource.data.studentId && 
        resource.data.status == 'active' &&
        request.resource.data.studentId == resource.data.studentId &&
        request.resource.data.quizId == resource.data.quizId
      );

      // Listing: Restricted to Admins or specific Student queries
      allow list: if isSignedIn() && (isAdmin() || (request.query.limit != null && request.query.limit <= 500));
    }

    // ==========================================
    // CATCH-ALL PROTECTION
    // ==========================================

    // Global fallback for system owner (root bypass)
    match /{document=**} {
      allow read, write: if isSystemOwner();
    }
  }
}

