              setRole(isSystemOwner ? "admin" : data.role);
              setLoading(false);
            } else {
              setProfile(null);
              setRole(isSystemOwner ? "admin" : null);
              setLoading(false);
            }
          }, (error) => {
            console.error("Profile sync error:", error);
            // If listener fails due to permission but we know they are owner, force admin
            if (isSystemOwner) {
              setRole("admin");
            }
            setLoading(false);
          });
        } catch (error) {
          console.error("Auth initialization failure:", error);
          // Fixed: isSystemOwner is now accessible here
          if (isSystemOwner) setRole("admin");
          setLoading(false);
        }
      } else {
        setProfile(null);
        setRole(null);
        setLoading(false);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubscribeProfile) unsubscribeProfile();
    };
  }, []);

  const logout = async () => {
    await auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, profile, role, loading, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};

