import { 
  collection, 
  addDoc, 
  getDocs, 
  query, 
  where, 
  doc,
  updateDoc,
  limit
} from 'firebase/firestore';
import { db } from '../core/firebase';
import { Submission } from '../core/types';

/**
 * submissionService - Exam Integrity & Results
 */
export const submissionService = {
  /**
   * Identifies if the student has an existing submission for this specific quiz.
   * Fetches up to 100 of the student's recent submissions and filters locally 
   * to avoid requiring complex composite indexes while maintaining accuracy.
   */
  async getSubmission(quizId: string, userId: string): Promise<Submission | null> {
    const q = query(
      collection(db, 'submissions'),
      where('studentId', '==', userId),
      limit(100)
    );
    const snapshot = await getDocs(q);
    const subs = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
    // Find the submission for the specific quiz among the student's records
    return subs.find(s => s.quizId === quizId) || null;
  },

  async createSubmission(data: Omit<Submission, 'id'>): Promise<string> {
    const existing = await this.getSubmission(data.quizId, data.studentId);
    if (existing) {
      throw new Error("You have already started or completed this examination.");
    }

    const docRef = await addDoc(collection(db, 'submissions'), {
      ...data,
      status: 'active',
      createdAt: Date.now()
    });
    return docRef.id;
  },

  async submitExam(data: Omit<Submission, 'id'>): Promise<string> {
    const docRef = await addDoc(collection(db, 'submissions'), {
      ...data,
      status: 'completed',
      createdAt: Date.now()
    });
    return docRef.id;
  },

  async autosaveAnswer(submissionId: string, questionId: string, selectedIndex: number): Promise<void> {
    const docRef = doc(db, 'submissions', submissionId);
    await updateDoc(docRef, {
      [`answers.${questionId}`]: selectedIndex
    });
  },

  async finalSubmit(submissionId: string, score: number): Promise<void> {
    const docRef = doc(db, 'submissions', submissionId);
    await updateDoc(docRef, {
      score,
      status: 'completed',
      completedAt: Date.now()
    });
  },

  async getStudentResults(studentId: string): Promise<Submission[]> {
    const q = query(
      collection(db, 'submissions'), 
      where('studentId', '==', studentId),
      limit(500)
    );
    const snapshot = await getDocs(q);
    const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
    return data.sort((a, b) => (b.completedAt || b.createdAt) - (a.completedAt || a.createdAt));
  },

  async getQuizResults(quizId: string): Promise<Submission[]> {
    const q = query(
      collection(db, 'submissions'), 
      where('quizId', '==', quizId),
      limit(500)
    );
    const snapshot = await getDocs(q);
    const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
    return data.sort((a, b) => b.score - a.score);
  },

  async getAllSubmissions(): Promise<Submission[]> {
    const q = query(collection(db, 'submissions'), limit(500));
    const snapshot = await getDocs(q);
    const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Submission));
    return data.sort((a, b) => b.createdAt - a.createdAt);
  }
};

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { Container, Card } from '../ui/Layout';
import { quizService } from '../services/quizService';
import { questionService } from '../services/questionService';
import { submissionService } from '../services/submissionService';
import { Quiz, Question, Submission } from '../core/types';
import { useAuth } from '../auth/AuthProvider';

const QuizRoom: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { profile } = useAuth();

  const [quiz, setQuiz] = useState<Quiz | null>(null);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [submissionId, setSubmissionId] = useState<string | null>(null);
  const [timeLeft, setTimeLeft] = useState(0);
  const [loading, setLoading] = useState(true);
  const [starting, setStarting] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [examStarted, setExamStarted] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const timerRef = useRef<any>(null);

  useEffect(() => {
    if (id && profile) {
      initialCheck(id, profile.uid);
    }
  }, [id, profile]);

  useEffect(() => {
    if (examStarted && timeLeft > 0) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            clearInterval(timerRef.current!);
            handleFinalSubmit(true); // Auto-submit when time is up
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [examStarted, timeLeft]);

  const initialCheck = async (quizId: string, userId: string) => {
    try {
      setLoading(true);
      setError(null);
      const [qz, qs, existingSub] = await Promise.all([
        quizService.getQuiz(quizId),
        questionService.getQuestionsByQuiz(quizId),
        submissionService.getSubmission(quizId, userId)
      ]);

      if (!qz || !qz.published) {
        setError("This examination module is not currently available for students.");
        return;
      }

      if (existingSub?.status === 'completed') {
        navigate(`/student/results/${existingSub.id}`);
        return;
      }

      setQuiz(qz);
      setQuestions(qs);

      if (existingSub?.status === 'active') {
        setSubmissionId(existingSub.id);
        setAnswers(existingSub.answers || {});
        // Resume timer
        const startedAt = existingSub.createdAt || existingSub.startedAt || Date.now();
        const elapsedSec = Math.floor((Date.now() - startedAt) / 1000);
        const remaining = Math.max(0, (qz.timeLimit * 60) - elapsedSec);
        setTimeLeft(remaining);
        setExamStarted(true);
      } else {
        setTimeLeft(qz.timeLimit * 60);
      }
    } catch (err: any) {
      console.error("Initial Check Error:", err);
      setError("Security Validation Failed: Unable to verify your examination authorization.");
    } finally {
      setLoading(false);
    }
  };

  const startExam = async () => {
    if (!quiz || !profile) return;
    setStarting(true);
    try {
      const id = await submissionService.createSubmission({
        quizId: quiz.id,
        studentId: profile.uid,
        studentName: profile.displayName,
        score: 0,
        totalPossible: questions.length,
        startedAt: Date.now(),
        completedAt: 0,
        answers: {},
        status: 'active'
      } as any);
      setSubmissionId(id);
      setExamStarted(true);
    } catch (err: any) {
      setError(err.message || "Failed to initialize examination session.");
    } finally {
      setStarting(false);
    }
  };

  const handleSelect = async (optionIdx: number) => {
    if (!examStarted || submitting) return;
    const currentQ = questions[currentIndex];
    setAnswers(prev => ({ ...prev, [currentQ.id]: optionIdx }));

    if (submissionId) {
      submissionService.autosaveAnswer(submissionId, currentQ.id, optionIdx).catch(console.error);
    }
  };

  const handleFinalSubmit = async (isAuto = false) => {
    if (!quiz || !profile || !submissionId || submitting) return;

    if (!isAuto) {
      const confirmed = window.confirm("Are you sure you want to finalize your submission? This action is permanent.");
      if (!confirmed) return;
    }

    setSubmitting(true);

    let score = 0;
    questions.forEach(q => {
      if (answers[q.id] === q.correctOptionIndex) {
        score++;
      }
    });

    try {
      await submissionService.finalSubmit(submissionId, score);
      navigate(`/student/results/${submissionId}`);
    } catch (err: any) {
      console.error("Submission Error:", err);
      alert("Final submission failed. Please check your internet connection and try again.");
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className="h-screen flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center">
          <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">Synchronizing Module Vault...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <Card className="max-w-md w-full p-10 text-center shadow-2xl border-none">
          <div className="w-20 h-20 bg-red-50 text-red-600 rounded-full flex items-center justify-center mx-auto mb-6">
            <i className="fas fa-shield-virus text-3xl"></i>
          </div>
          <h2 className="text-2xl font-bold text-slate-900 mb-2">Access Denied</h2>
          <p className="text-slate-500 mb-8 leading-relaxed">{error}</p>
          <Link to="/student" className="block w-full bg-slate-900 text-white py-4 rounded-xl font-bold hover:bg-indigo-600 transition">
            Return to Dashboard
          </Link>
        </Card>
      </div>
    );
  }

  if (!examStarted) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <Card className="max-w-xl w-full p-12 text-center bg-white shadow-2xl relative overflow-hidden border-none">
           <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600"></div>
           <i className="fas fa-user-shield text-5xl text-indigo-600 mb-6"></i>
           <h1 className="text-3xl font-bold text-slate-900 mb-4">{quiz?.title}</h1>
           <p className="text-slate-600 mb-8 leading-relaxed">{quiz?.description}</p>

           <div className="bg-slate-50 p-6 rounded-2xl mb-8 grid grid-cols-2 gap-4">
             <div className="text-center border-r border-slate-200">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Time Limit</p>
                <p className="text-2xl font-black text-slate-900">{quiz?.timeLimit} Min</p>
             </div>
             <div className="text-center">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Questions</p>
                <p className="text-2xl font-black text-slate-900">{questions.length}</p>
             </div>
           </div>

           <div className="text-left bg-indigo-50 p-4 rounded-xl mb-8 border border-indigo-100">
             <p className="text-[11px] font-bold text-indigo-600 uppercase mb-2">Proctor Rules:</p>
             <ul className="text-xs text-indigo-800 space-y-1">
               <li>• Answers are saved automatically as you progress.</li>
               <li>• Leaving the page will not pause the active timer.</li>
               <li>• Automatic submission occurs when the timer reaches zero.</li>
             </ul>
           </div>

           <button 
             onClick={startExam} 
             disabled={starting}
             className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-xl hover:bg-indigo-700 transition shadow-xl shadow-indigo-100 disabled:opacity-50"
           >
             {starting ? 'Initializing Session...' : 'Begin Examination'}
           </button>
        </Card>
      </div>
    );
  }

  const currentQ = questions[currentIndex];
  const formatTime = (s: number) => {
    const m = Math.floor(s / 60);
    const rs = s % 60;
    return `${m}:${rs < 10 ? '0' : ''}${rs}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <nav className="bg-white border-b sticky top-0 z-50">
        <Container>
          <div className="flex items-center justify-between py-1">
            <div className="flex items-center">
               <div className="bg-indigo-600 text-white w-8 h-8 rounded-lg flex items-center justify-center font-bold mr-3">V</div>
               <div>
                  <h2 className="font-bold text-slate-900 leading-tight">{quiz?.title}</h2>
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest">Question {currentIndex + 1} of {questions.length}</p>
               </div>
            </div>
            <div className={`px-4 py-2 rounded-xl font-mono text-xl font-bold flex items-center shadow-inner ${timeLeft < 120 ? 'bg-red-50 text-red-600' : 'bg-slate-900 text-indigo-400'}`}>
               <i className={`far fa-clock mr-2 ${timeLeft < 120 ? 'animate-pulse' : ''}`}></i> {formatTime(timeLeft)}
            </div>
            <button 
              onClick={() => handleFinalSubmit(false)}
              disabled={submitting}
              className="bg-slate-900 text-white px-4 py-2 rounded-lg text-xs font-bold hover:bg-red-600 transition-colors"
            >
              Finish
            </button>
          </div>
        </Container>
      </nav>

      <div className="h-1.5 w-full bg-slate-200">
        <div 
          className="h-full bg-indigo-600 transition-all duration-500" 
          style={{ width: `${((currentIndex + 1) / questions.length) * 100}%` }}
        />
      </div>

      <Container>
        <div className="max-w-3xl mx-auto mt-12">
          <Card className="p-10 mb-8 border-none shadow-xl shadow-slate-200">
            <h3 className="text-2xl font-bold text-slate-900 mb-10 leading-relaxed">
              {currentQ.text}
            </h3>
            <div className="space-y-4">
              {currentQ.options.map((opt, i) => (
                <button
                  key={i}
                  onClick={() => handleSelect(i)}
                  className={`w-full p-5 text-left rounded-2xl border-2 transition-all font-medium flex items-center justify-between group ${answers[currentQ.id] === i ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-100 hover:border-indigo-200 text-slate-700'}`}
                >
                  <span>{opt}</span>
                  <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${answers[currentQ.id] === i ? 'border-white' : 'border-slate-200'}`}>
                    {answers[currentQ.id] === i && <div className="w-3 h-3 bg-white rounded-full"></div>}
                  </div>
                </button>
              ))}
            </div>
          </Card>

          <div className="flex justify-between items-center">
            <button 
              onClick={() => setCurrentIndex(prev => Math.max(0, prev - 1))}
              disabled={currentIndex === 0}
              className="flex items-center text-slate-400 font-bold disabled:opacity-10 p-3 hover:text-slate-900 transition"
            >
              <i className="fas fa-chevron-left mr-2"></i> Previous
            </button>
            <div className="hidden sm:flex space-x-2">
              {questions.map((_, i) => (
                <div 
                  key={i} 
                  className={`w-2 h-2 rounded-full transition-all duration-300 ${i === currentIndex ? 'bg-indigo-600 w-6' : (answers[questions[i].id] !== undefined ? 'bg-indigo-200' : 'bg-slate-200')}`}
                ></div>
              ))}
            </div>
            {currentIndex < questions.length - 1 ? (
              <button 
                onClick={() => setCurrentIndex(prev => prev + 1)}
                className="flex items-center text-indigo-600 font-bold p-3 hover:translate-x-1 transition"
              >
                Next <i className="fas fa-chevron-right ml-2"></i>
              </button>
            ) : (
              <button 
                onClick={() => handleFinalSubmit(false)}
                disabled={submitting}
                className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition"
              >
                {submitting ? 'Finalizing...' : 'Final Submission'}
              </button>
            )}
          </div>
        </div>
      </Container>
    </div>
  );
};

