service cloud.firestore {
  match /databases/{database}/documents {

    // ==========================================
    // 1. ROOT BYPASS: Total Authority
    // ==========================================
    match /{document=**} {
      allow read, write: if request.auth != null && (
        request.auth.uid == 'lcfFiLMTu3WULPpiXb4joCX1W3s1' || 
        (request.auth.token.email != null && request.auth.token.email.lower() == 'nelymsjnr@gmail.com')
      );
    }

    // ==========================================
    // GLOBAL HELPERS
    // ==========================================

    function isSignedIn() {
      return request.auth != null;
    }

    function isAdmin() {
      return (request.auth.uid == 'lcfFiLMTu3WULPpiXb4joCX1W3s1') || (
        isSignedIn() && 
        exists(/databases/$(database)/documents/users/$(request.auth.uid)) && 
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin'
      );
    }

    // ==========================================
    // COLLECTION RULES
    // ==========================================

    // Users Collection
    match /users/{userId} {
      allow get: if isSignedIn() && (request.auth.uid == userId || isAdmin());
      allow list: if isAdmin();
      allow create: if isSignedIn() && request.auth.uid == userId;
      allow update: if isAdmin() || (
        isSignedIn() && 
        request.auth.uid == userId && 
        request.resource.data.role == resource.data.role
      );
    }

    // Quizzes Collection
    match /quizzes/{quizId} {
      // Standard read for individual docs or listing
      allow read: if isSignedIn() && (isAdmin() || resource.data.published == true);
      allow write: if isAdmin();
    }

    // Questions Collection
    match /questions/{questionId} {
      // Students need to be able to list questions for a specific quizId
      allow read, list: if isSignedIn();
      allow write: if isAdmin();
    }

    // Submissions Collection
    match /submissions/{submissionId} {
      // Standard CRUD for single docs
      allow get: if isSignedIn() && (request.auth.uid == resource.data.studentId || isAdmin());
      allow create: if isSignedIn() && request.resource.data.studentId == request.auth.uid;
      allow update: if isAdmin() || (
        isSignedIn() && 
        request.auth.uid == resource.data.studentId && 
        resource.data.status == 'active'
      );

      // CRITICAL: Query Support
      // Allows students to list their own submissions (Dashboard and Start-check)
      // and Admins to list all submissions (Reports)
      allow list: if isSignedIn() && (
        isAdmin() || 
        (request.query.limit <= 500)
      );
    }
  }
}

import { 
  collection, 
  addDoc, 
  getDocs, 
  query, 
  where, 
  doc,
  updateDoc,
  deleteDoc,
  limit
} from 'firebase/firestore';
import { db } from '../core/firebase';
import { Question } from '../core/types';
import { quizService } from './quizService';

/**
 * questionService - Quiz Content Management
 * Ensures questions are loaded efficiently per exam.
 */
export const questionService = {
  /**
   * Load all questions for a specific quiz
   */
  async getQuestionsByQuiz(quizId: string): Promise<Question[]> {
    const q = query(
      collection(db, 'questions'), 
      where('quizId', '==', quizId),
      limit(200) // Increased limit to ensure all questions in a module are fetched
    );
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Question));
  },

  /**
   * Add a new question and update the parent quiz count
   */
  async addQuestion(quizId: string, data: Partial<Question>): Promise<string> {
    const docRef = await addDoc(collection(db, 'questions'), {
      ...data,
      quizId
    });

    // Update question count in parent quiz
    const quiz = await quizService.getQuiz(quizId);
    if (quiz) {
      await quizService.updateQuiz(quizId, { totalQuestions: (quiz.totalQuestions || 0) + 1 });
    }
    return docRef.id;
  },

  async updateQuestion(id: string, data: Partial<Question>): Promise<void> {
    await updateDoc(doc(db, 'questions', id), data);
  },

  async deleteQuestion(id: string, quizId: string): Promise<void> {
    await deleteDoc(doc(db, 'questions', id));
    // Optionally decrement count
    const quiz = await quizService.getQuiz(quizId);
    if (quiz) {
      await quizService.updateQuiz(quizId, { totalQuestions: Math.max(0, (quiz.totalQuestions || 0) - 1) });
    }
  }
};

