rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // ==========================================
    // 1. ROOT BYPASS: Total Authority
    // ==========================================
    // Provides immediate access to the System Owner to prevent lockouts.
    match /{document=**} {
      allow read, write: if request.auth != null && (
        request.auth.uid == 'lcfFiLMTu3WULPpiXb4joCX1W3s1' || 
        (request.auth.token.email != null && request.auth.token.email.lower() == 'nelymsjnr@gmail.com')
      );
    }

    // ==========================================
    // GLOBAL HELPERS
    // ==========================================

    function isSignedIn() {
      return request.auth != null;
    }

    // Refined isAdmin to avoid recursive document lookups
    function isAdmin() {
      let isOwner = request.auth.uid == 'lcfFiLMTu3WULPpiXb4joCX1W3s1' || 
                    (request.auth.token.email != null && request.auth.token.email.lower() == 'nelymsjnr@gmail.com');

      // If not the owner, check the user profile role attribute
      // We use exists() first to ensure we don't trigger errors on new accounts
      return isOwner || (
        isSignedIn() && 
        exists(/databases/$(database)/documents/users/$(request.auth.uid)) && 
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin'
      );
    }

    // ==========================================
    // COLLECTION RULES
    // ==========================================

    // Users Collection: Profiles and Roles
    match /users/{userId} {
      // A user can always read their own profile to verify their role
      allow get: if isSignedIn() && request.auth.uid == userId;
      // Admins can list and manage all users
      allow read, list: if isAdmin();
      allow create: if isSignedIn() && request.auth.uid == userId;
      allow update: if isAdmin() || (isSignedIn() && request.auth.uid == userId && request.resource.data.role == resource.data.role);
    }

    // Quizzes Collection: Module Metadata
    match /quizzes/{quizId} {
      // Students can only read quizzes that are published
      // Admins can read all quizzes (drafts included)
      allow read, list: if isSignedIn() && (
        isAdmin() || 
        (exists(/databases/$(database)/documents/quizzes/$(quizId)) && get(/databases/$(database)/documents/quizzes/$(quizId)).data.published == true) ||
        (resource != null && resource.data.published == true)
      );
      allow write: if isAdmin();
    }

    // Questions Collection: Examination Content
    match /questions/{questionId} {
      // Students can read/list questions for exams
      // Security Layer: Students can list questions if they are signed in.
      // The QuizRoom component will handle filtering by quizId.
      allow read, list: if isSignedIn();
      allow write: if isAdmin();
    }

    // Submissions Collection: Progress and Results
    match /submissions/{submissionId} {
      allow get: if isSignedIn() && (request.auth.uid == resource.data.studentId || isAdmin());
      allow create: if isSignedIn() && request.resource.data.studentId == request.auth.uid;
      allow update: if isAdmin() || (
        isSignedIn() && 
        request.auth.uid == resource.data.studentId && 
        resource.data.status == 'active'
      );

      // Support for the Dashboard "In Progress" checks and results history
      allow list: if isSignedIn() && (
        isAdmin() || 
        (request.query.limit <= 500)
      );
    }
  }
}

import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Navbar, Container, Card } from '../ui/Layout';
import { questionService } from '../services/questionService';
import { quizService } from '../services/quizService';
import { Quiz, Question } from '../core/types';

const QuestionBuilder: React.FC = () => {
  const { quizId } = useParams<{ quizId: string }>();
  const [quiz, setQuiz] = useState<Quiz | null>(null);
  const [savedQuestions, setSavedQuestions] = useState<Question[]>([]);
  const [stagedQuestions, setStagedQuestions] = useState<Omit<Question, 'id' | 'quizId'>[]>([]);
  const [loading, setLoading] = useState(true);

  // Form State
  const [text, setText] = useState('');
  const [options, setOptions] = useState(['', '', '', '']);
  const [correct, setCorrect] = useState(0);
  const [isDeploying, setIsDeploying] = useState(false);

  useEffect(() => {
    if (quizId) loadData(quizId);
  }, [quizId]);

  const loadData = async (id: string) => {
    try {
      const [qz, qs] = await Promise.all([
        quizService.getQuiz(id),
        questionService.getQuestionsByQuiz(id)
      ]);
      setQuiz(qz);
      setSavedQuestions(qs);
    } finally {
      setLoading(false);
    }
  };

  const addToStage = (e: React.FormEvent) => {
    e.preventDefault();
    const newQuestion = {
      text,
      options: [...options],
      correctOptionIndex: correct
    };
    setStagedQuestions([...stagedQuestions, newQuestion]);

    // Reset Form
    setText('');
    setOptions(['', '', '', '']);
    setCorrect(0);
  };

  const removeFromStage = (index: number) => {
    const newStage = [...stagedQuestions];
    newStage.splice(index, 1);
    setStagedQuestions(newStage);
  };

  const handleBatchDeploy = async () => {
    if (!quizId || stagedQuestions.length === 0 || isDeploying) return;

