service cloud.firestore {
  match /databases/{database}/documents {

    // ==========================================
    // 1. ROOT BYPASS: Total Authority
    // ==========================================
    // Provides immediate access to the System Owner to prevent lockouts.
    match /{document=**} {
      allow read, write: if request.auth != null && (
        request.auth.uid == 'lcfFiLMTu3WULPpiXb4joCX1W3s1' || 
        (request.auth.token.email != null && request.auth.token.email.lower() == 'nelymsjnr@gmail.com')
      );
    }

    // ==========================================
    // GLOBAL HELPERS
    // ==========================================

    function isSignedIn() {
      return request.auth != null;
    }

    // Refined isAdmin to avoid recursive document lookups
    function isAdmin() {
      let isOwner = request.auth.uid == 'lcfFiLMTu3WULPpiXb4joCX1W3s1' || 
                    (request.auth.token.email != null && request.auth.token.email.lower() == 'nelymsjnr@gmail.com');

      // If not the owner, check the user profile role attribute
      return isOwner || (
        isSignedIn() && 
        exists(/databases/$(database)/documents/users/$(request.auth.uid)) && 
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin'
      );
    }

    // ==========================================
    // COLLECTION RULES
    // ==========================================

    // Users Collection: Profiles and Roles
    match /users/{userId} {
      allow get: if isSignedIn() && request.auth.uid == userId;
      allow read, list: if isAdmin();
      allow create: if isSignedIn() && request.auth.uid == userId;
      allow update: if isAdmin() || (isSignedIn() && request.auth.uid == userId && request.resource.data.role == resource.data.role);
    }

    // Quizzes Collection: Module Metadata
    match /quizzes/{quizId} {
      // Allow students to read/list ONLY if the exam is published
      // Admins bypass this check via isAdmin()
      allow read, list: if isSignedIn() && (
        isAdmin() || 
        (resource != null && resource.data.published == true)
      );

      // Explicit Administrative Lifecycle Control
      // Allows deletion of both draft and published examinations
      allow create, update, delete: if isAdmin();
    }

    // Questions Collection: Examination Content
    match /questions/{questionId} {
      // Students can synchronize questions for active sessions
      allow read, list: if isSignedIn();

      // Admins can manage the question vault, including batch deletions
      allow create, update, delete: if isAdmin();
    }

    // Submissions Collection: Progress and Results
    match /submissions/{submissionId} {
      allow get: if isSignedIn() && (request.auth.uid == resource.data.studentId || isAdmin());
      allow create: if isSignedIn() && request.resource.data.studentId == request.auth.uid;
      allow update: if isAdmin() || (
        isSignedIn() && 
        request.auth.uid == resource.data.studentId && 
        resource.data.status == 'active'
      );
      allow list: if isSignedIn() && (isAdmin() || request.query.limit <= 500);

      // Academic Integrity: Only Admins can delete submission records
      // Students cannot remove their attempt history.
      allow delete: if isAdmin();
    }
  }
}

