    function isSignedIn() {
      return request.auth != null;
    }

    function isAdmin() {
      let isOwner = request.auth.uid == 'lcfFiLMTu3WULPpiXb4joCX1W3s1' || 
                    (request.auth.token.email != null && request.auth.token.email.lower() == 'nelymsjnr@gmail.com');

      return isOwner || (
        isSignedIn() && 
        exists(/databases/$(database)/documents/users/$(request.auth.uid)) && 
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin'
      );
    }

    // ==========================================
    // COLLECTION RULES
    // ==========================================

    // User Profiles
    match /users/{userId} {
      allow get: if isSignedIn() && request.auth.uid == userId;
      allow read, list: if isAdmin();
      allow create: if isSignedIn() && request.auth.uid == userId;
      allow update: if isAdmin() || (isSignedIn() && request.auth.uid == userId && request.resource.data.role == resource.data.role);
    }

    // Quiz Modules
    match /quizzes/{quizId} {
      // Students see only published exams; Admins see everything.
      allow read, list: if isSignedIn() && (
        isAdmin() || 
        (resource != null && resource.data.published == true)
      );

      // Admins can Create, Update, and DELETE (even if published)
      allow create, update, delete: if isAdmin();
    }

    // Question Bank
    match /questions/{questionId} {
      // Required for students to load exam content
      allow read, list: if isSignedIn();

      // Required for Admins to build and cascade-delete content
      allow create, update, delete: if isAdmin();
    }

    // Student Submissions
    match /submissions/{submissionId} {
      allow get: if isSignedIn() && (request.auth.uid == resource.data.studentId || isAdmin());
      allow create: if isSignedIn() && request.resource.data.studentId == request.auth.uid;
      allow update: if isAdmin() || (
        isSignedIn() && 
        request.auth.uid == resource.data.studentId && 
        resource.data.status == 'active'
      );
      allow list: if isSignedIn() && (isAdmin() || (request.query.limit <= 500 && request.auth.uid != null));

      // Academic record preservation: Only admins can delete history.
      allow delete: if isAdmin();
    }
  }
}

import { 
  collection, 
  addDoc, 
  getDocs, 
  getDoc, 
  doc, 
  query, 
  where, 
  updateDoc, 
  deleteDoc,
  onSnapshot,
  limit,
  writeBatch
} from 'firebase/firestore';
import { db } from '../core/firebase';
import { Quiz } from '../core/types';

/**
 * quizService - Exam Availability & Management
 */
export const quizService = {
  async getPublishedQuizzes(): Promise<Quiz[]> {
    const q = query(
      collection(db, 'quizzes'), 
      where('published', '==', true),
      limit(500)
    );
    const snapshot = await getDocs(q);
    const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Quiz));
    return data.sort((a, b) => b.createdAt - a.createdAt);
  },

  async getAllQuizzes(): Promise<Quiz[]> {
    // Explicit limit added to satisfy security rules for collection listing
    const q = query(collection(db, 'quizzes'), limit(500));
    const snapshot = await getDocs(q);
    const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Quiz));
    return data.sort((a, b) => b.createdAt - a.createdAt);
  },

  subscribeToQuizzes(callback: (quizzes: Quiz[]) => void) {
    const q = query(collection(db, 'quizzes'), limit(500));
    return onSnapshot(q, (snapshot) => {
      const data = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Quiz));
      callback(data.sort((a, b) => b.createdAt - a.createdAt));
    });
  },

  async getQuiz(id: string): Promise<Quiz | null> {
    const docSnap = await getDoc(doc(db, 'quizzes', id));
    return docSnap.exists() ? ({ id: docSnap.id, ...docSnap.data() } as Quiz) : null;
  },

  async createQuiz(data: Partial<Quiz>, uid: string): Promise<string> {
    const docRef = await addDoc(collection(db, 'quizzes'), {
      ...data,
      createdBy: uid,
      createdAt: Date.now(),
      published: false,
      totalQuestions: 0
    });
    return docRef.id;
  },

  async updateQuiz(id: string, data: Partial<Quiz>): Promise<void> {
    await updateDoc(doc(db, 'quizzes', id), data);
  },

  /**
   * Performs a permanent "Purge Delete" of the quiz.
   * Removes: The Quiz Doc, All associated Questions, and All Student Submissions.
   */
  async deleteQuiz(id: string): Promise<void> {
    const batch = writeBatch(db);

    // 1. Fetch all questions linked to this quiz
    const questionsQuery = query(collection(db, 'questions'), where('quizId', '==', id));
    const questionsSnapshot = await getDocs(questionsQuery);

    // 2. Fetch all submissions linked to this quiz (to remove from student history)
    const submissionsQuery = query(collection(db, 'submissions'), where('quizId', '==', id));
    const submissionsSnapshot = await getDocs(submissionsQuery);

    // 3. Add questions to deletion batch
    questionsSnapshot.docs.forEach((qDoc) => {
      batch.delete(qDoc.ref);
    });

    // 4. Add submissions to deletion batch
    submissionsSnapshot.docs.forEach((sDoc) => {
      batch.delete(sDoc.ref);
    });

    // 5. Delete the quiz document itself
    batch.delete(doc(db, 'quizzes', id));

    // 6. Commit the full batch
    await batch.commit();
  }
};

