                   <Link to={`/admin/files/${quiz.id}`} className="flex items-center justify-center p-4 bg-slate-50 text-slate-600 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-slate-100 transition-colors">
                      Resources
                   </Link>
