                <button 
                  onClick={() => togglePublish(quiz)} 
                  className={`mt-4 w-full py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${quiz.published ? 'text-red-500 bg-red-50 hover:bg-red-100 border border-red-100' : 'text-indigo-600 bg-indigo-50 hover:bg-indigo-100 border border-indigo-100'}`}
                >
                  {quiz.published ? 'Stop Distribution' : 'Publish to Students'}
