            <Card className="max-w-xl w-full p-10 relative border-none shadow-2xl animate-in zoom-in-95 max-h-[90vh] overflow-y-auto">
              <button onClick={() => setShowModal(false)} className="absolute top-6 right-6 text-slate-400 hover:text-slate-900 transition">
                <i className="fas fa-times text-xl"></i>
              </button>
              <h2 className="text-3xl font-black mb-8 text-slate-900 tracking-tight">New Module</h2>
              <form onSubmit={handleCreate} className="space-y-6">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Module Title</label>
                  <input type="text" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-4 border rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition bg-slate-50 border-slate-200" placeholder="e.g. Clinical Nursing Practice" required />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Curriculum Overview</label>
                  <textarea value={desc} onChange={e => setDesc(e.target.value)} className="w-full p-4 border rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition bg-slate-50 border-slate-200" placeholder="Brief description for student dashboard..." required />
                </div>

                <div className="grid grid-cols-2 gap-6">
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Duration (Minutes)</label>
                    <input type="number" value={time} onChange={e => setTime(Number(e.target.value))} className="w-full p-4 border rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition bg-slate-50 border-slate-200" required min="1" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Question Format</label>
                    <div className="grid grid-cols-3 gap-2">
                      {[2, 3, 4].map(num => (
                        <button
                          key={num}
                          type="button"
                          onClick={() => setOptionsCount(num)}
