                <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg hover:bg-indigo-600 shadow-xl shadow-slate-200 transition-all active:scale-[0.98]">Deploy Draft Registry</button>
              </form>
            </Card>
          </div>
        )}
      </Container>
    </div>
  );
};

export default QuizManagement;

import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Navbar, Container, Card } from '../ui/Layout';
import { questionService } from '../services/questionService';
import { quizService } from '../services/quizService';
import { Quiz, Question } from '../core/types';

const QuestionBuilder: React.FC = () => {
  const { quizId } = useParams<{ quizId: string }>();
  const [quiz, setQuiz] = useState<Quiz | null>(null);
  const [savedQuestions, setSavedQuestions] = useState<Question[]>([]);
  const [stagedQuestions, setStagedQuestions] = useState<Omit<Question, 'id' | 'quizId'>[]>([]);
  const [loading, setLoading] = useState(true);

  // Form State - Initialized with 4, but will sync with quiz data
  const [text, setText] = useState('');
  const [options, setOptions] = useState(['', '', '', '']);
  const [correct, setCorrect] = useState(0);
  const [isDeploying, setIsDeploying] = useState(false);

  useEffect(() => {
    if (quizId) loadData(quizId);
  }, [quizId]);

  const loadData = async (id: string) => {
    try {
      const [qz, qs] = await Promise.all([
        quizService.getQuiz(id),
        questionService.getQuestionsByQuiz(id)
      ]);
      setQuiz(qz);
      setSavedQuestions(qs);

      // Update options count based on quiz settings
      if (qz) {
        const count = qz.defaultOptionsCount || 4;
        setOptions(new Array(count).fill(''));
      }
    } finally {
      setLoading(false);
    }
  };

  const addToStage = (e: React.FormEvent) => {
    e.preventDefault();
    const newQuestion = {
      text,
      options: [...options],
      correctOptionIndex: correct
    };
    setStagedQuestions([...stagedQuestions, newQuestion]);

    // Reset Form to quiz defaults
    setText('');
    const count = quiz?.defaultOptionsCount || 4;
    setOptions(new Array(count).fill(''));
    setCorrect(0);
  };

  const removeFromStage = (index: number) => {
    const newStage = [...stagedQuestions];
    newStage.splice(index, 1);
    setStagedQuestions(newStage);
  };

  const handleBatchDeploy = async () => {
    if (!quizId || stagedQuestions.length === 0 || isDeploying) return;

    setIsDeploying(true);
    try {
      // Deploy each staged question sequentially
      for (const q of stagedQuestions) {
        await questionService.addQuestion(quizId, q as any);
      }

      // Refresh saved list and clear stage
      const qs = await questionService.getQuestionsByQuiz(quizId);
      setSavedQuestions(qs);
      setStagedQuestions([]);
      alert(`Successfully deployed ${stagedQuestions.length} questions to the examination vault.`);
    } catch (err) {
      console.error("Batch Deployment Error:", err);
      alert("An error occurred during deployment. Some questions may not have been saved.");
    } finally {
      setIsDeploying(false);
    }
  };

  if (loading) return (
    <div className="h-screen flex items-center justify-center bg-slate-50">
      <div className="flex flex-col items-center">
        <div className="w-10 h-10 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Opening Registry...</p>
      </div>
    </div>
  );

  const nextQuestionNumber = savedQuestions.length + stagedQuestions.length + 1;

  return (
    <div className="min-h-screen bg-slate-50">
      <Navbar />
      <Container>
        <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
          <div>
            <Link to="/admin/quizzes" className="text-indigo-600 text-sm font-bold flex items-center mb-2 hover:translate-x-[-4px] transition-transform w-fit">
              <i className="fas fa-arrow-left mr-2"></i> Back to Module Registry
            </Link>
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">Curriculum Builder</h1>
            <p className="text-slate-500 font-medium">{quiz?.title}</p>
          </div>
          <div className="flex items-center space-x-3">
             <div className="bg-white px-5 py-3 rounded-2xl border border-slate-200 shadow-sm text-center min-w-[100px]">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Vault Registry</p>
                <p className="text-xl font-black text-slate-900">{savedQuestions.length} Items</p>
             </div>
             <div className="bg-indigo-50 px-5 py-3 rounded-2xl border border-indigo-100 shadow-sm text-center min-w-[100px]">
                <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-1">Format</p>
                <p className="text-xl font-black text-indigo-700">{quiz?.defaultOptionsCount || 4} Opts</p>
             </div>
             {stagedQuestions.length > 0 && (
               <div className="bg-amber-50 px-5 py-3 rounded-2xl border border-amber-100 shadow-sm animate-pulse text-center min-w-[100px]">
                  <p className="text-[10px] font-black text-amber-600 uppercase tracking-widest mb-1">Staging Area</p>
                  <p className="text-xl font-black text-amber-700">{stagedQuestions.length} New</p>
               </div>
             )}
          </div>
        </div>

        <div className="grid lg:grid-cols-12 gap-8 items-start">
           {/* Form Column */}
           <div className="lg:col-span-5 sticky top-24">
              <Card className="p-8 border-none shadow-xl shadow-slate-200">
                <div className="flex items-center justify-between mb-8">
                   <h2 className="text-xl font-bold text-slate-900">Composer</h2>
                   <span className="bg-indigo-600 text-white text-[11px] font-black px-3 py-1 rounded-full uppercase tracking-tighter">
                     Item #{nextQuestionNumber}
                   </span>
                </div>

                <form onSubmit={addToStage} className="space-y-6">
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Question Inquiry</label>
                      <textarea 
                        value={text}
                        onChange={e => setText(e.target.value)}
                        className="w-full p-4 border rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition min-h-[140px] text-slate-700 font-medium"
                        placeholder="e.g. Identify the primary advantage of utilizing a hash map for lookups."
                        required
                      />
                   </div>

                   <div className="space-y-3">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Response Options</label>
                      {options.map((opt, i) => (
                        <div key={i} className="flex items-center space-x-3 group">
                          <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-xs transition ${correct === i ? 'bg-green-500 text-white shadow-lg' : 'bg-slate-100 text-slate-400'}`}>
                             {String.fromCharCode(65 + i)}
                          </div>
                          <input 
                            type="text" 
                            value={opt}
                            onChange={e => {
                              const n = [...options];
                              n[i] = e.target.value;
                              setOptions(n);
                            }}
                            placeholder={`Enter Option ${i+1}`}
                            className={`flex-1 p-3 border rounded-xl text-sm transition ${correct === i ? 'border-green-200 bg-green-50/30' : 'bg-white'}`}
                            required
                          />
                          <button 
                            type="button"
                            onClick={() => setCorrect(i)}
                            className={`p-2 transition ${correct === i ? 'text-green-600' : 'text-slate-200 hover:text-indigo-400'}`}
                          >
                             <i className={`fas ${correct === i ? 'fa-check-circle' : 'fa-circle'} text-lg`}></i>
                          </button>
                        </div>
                      ))}
                   </div>

                   <button 
                    type="submit" 
                    className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold hover:bg-indigo-600 transition shadow-xl shadow-slate-100"
                   >
                     <i className="fas fa-plus mr-2"></i> Add to Staging Queue
                   </button>
                </form>
              </Card>
           </div>

           {/* Sequence Column */}
           <div className="lg:col-span-7 space-y-6">
              {/* Staging Area Header */}
              {stagedQuestions.length > 0 && (
                <div className="bg-amber-600 rounded-2xl p-6 text-white shadow-xl shadow-amber-100 flex items-center justify-between">
                   <div>
                      <h3 className="font-bold text-lg">Staged for Deployment</h3>
                      <p className="text-amber-100 text-xs">These items are locally cached. Click deploy to synchronize with the vault.</p>
                   </div>
                   <button 
                    onClick={handleBatchDeploy}
                    disabled={isDeploying}
                    className="bg-white text-amber-700 px-6 py-3 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition disabled:opacity-50"
                   >
                     {isDeploying ? 'Deploying...' : 'Deploy to Examination'}
                   </button>
                </div>
              )}

              <h2 className="text-xl font-bold text-slate-900 flex items-center px-2">
                <span className="w-2 h-8 bg-indigo-600 rounded-full mr-3"></span>
                Sequence Preview
              </h2>

              <div className="space-y-4">
                 {/* Staged Items */}
                 {stagedQuestions.map((q, idx) => (
                   <Card key={`staged-${idx}`} className="p-6 border-amber-200 bg-amber-50/30 shadow-sm relative group overflow-hidden">
                     <div className="absolute top-0 right-0 p-2">
                        <span className="bg-amber-100 text-amber-700 text-[9px] font-black px-2 py-0.5 rounded-full uppercase">Staged / Unsaved</span>
                     </div>
                     <div className="flex justify-between items-start mb-4">
                        <span className="text-amber-600 font-black text-sm">#{savedQuestions.length + idx + 1}</span>
                        <button 
                          onClick={() => removeFromStage(idx)}
                          className="text-amber-300 hover:text-red-500 transition opacity-0 group-hover:opacity-100"
                        >
                          <i className="fas fa-times-circle"></i>
                        </button>
                     </div>
                     <p className="font-bold text-slate-800 mb-6 text-lg leading-snug">{q.text}</p>
                     <div className="grid grid-cols-2 gap-3">
                        {q.options.map((opt, i) => (
                          <div key={i} className={`p-3 rounded-xl border text-sm flex items-center ${i === q.correctOptionIndex ? 'bg-green-100 border-green-200 text-green-700 font-bold' : 'bg-white border-slate-100 text-slate-400'}`}>
                            <span className="w-5 h-5 flex items-center justify-center rounded bg-white/50 mr-2 text-[10px]">{String.fromCharCode(65+i)}</span>
                            {opt}
                          </div>
                        ))}
                     </div>
                   </Card>
                 ))}

                 {/* Saved Items */}
                 {savedQuestions.length === 0 && stagedQuestions.length === 0 ? (
                   <div className="p-24 text-center border-4 border-dashed rounded-3xl text-slate-300 border-slate-200">
                      <i className="fas fa-layer-group text-6xl mb-6 opacity-10"></i>
                      <p className="text-lg font-bold">Registry Empty</p>
                      <p className="text-sm">Begin composing questions in the composer panel.</p>
                   </div>
                 ) : (
                   savedQuestions.map((q, idx) => (
                     <Card key={q.id} className="p-6 border-slate-100 hover:shadow-md transition">
                       <div className="flex justify-between items-start mb-4">
                          <span className="text-indigo-600 font-black text-sm">#{idx + 1}</span>
                          <div className="flex space-x-2">
                             <span className="bg-slate-50 text-slate-400 text-[9px] font-black px-2 py-0.5 rounded-full uppercase">In Vault</span>
                             <button 
                                onClick={async () => {
                                  if(confirm("Permanently remove this item from the module vault?")) {
                                    await questionService.deleteQuestion(q.id, quizId!);
                                    loadData(quizId!);
                                  }
                                }}
                                className="text-slate-200 hover:text-red-500 transition"
                             >
                                <i className="fas fa-trash-alt text-xs"></i>
                             </button>
                          </div>
                       </div>
                       <p className="font-bold text-slate-700 mb-6 text-lg leading-snug">{q.text}</p>
                       <div className="grid grid-cols-2 gap-3">
                          {q.options.map((opt, i) => (
                            <div key={i} className={`p-3 rounded-xl border text-sm flex items-center ${i === q.correctOptionIndex ? 'bg-indigo-50 border-indigo-100 text-indigo-700 font-bold' : 'bg-slate-50 border-slate-50 text-slate-500'}`}>
                              <span className="w-5 h-5 flex items-center justify-center rounded bg-white/50 mr-2 text-[10px] font-black">{String.fromCharCode(65+i)}</span>
                              {opt}
                            </div>
                          ))}
                       </div>
                     </Card>
                   ))
                 )}
              </div>
           </div>
        </div>
      </Container>
    </div>
  );
};

export default QuestionBuilder;

import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { authService } from '../auth/authService';
import { UserRole } from '../core/types';

interface LoginProps {
  isSignup?: boolean;
}

const Login: React.FC<LoginProps> = ({ isSignup = false }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [displayName, setDisplayName] = useState('');
  const [role, setRole] = useState<UserRole>('student');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      if (isSignup) {
        // Sign up with default student role. 
        // Note: authService.signup automatically promotes system owner email to admin.
        await authService.signup(email, password, displayName, role);
      } else {
        // Login logic
        await authService.login(email, password);
      }
      // Redirect to dispatcher which handles role-based routing
      navigate('/dispatch');
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center px-4">
      <div className="max-w-md w-full bg-white rounded-2xl shadow-xl p-8 space-y-8 border border-slate-100">
        <div className="text-center">
          <Link to="/" className="text-3xl font-extrabold text-indigo-600">VSEFA</Link>
          <h2 className="mt-6 text-3xl font-bold text-slate-900">
            {isSignup ? 'Create account' : 'Welcome back'}
          </h2>
          <p className="mt-2 text-slate-500">
            {isSignup ? 'Join the virtual academy' : 'Sign in to your dashboard'}
          </p>
        </div>

        {error && (
          <div className="bg-red-50 text-red-600 p-4 rounded-lg text-sm font-medium border border-red-100 animate-pulse">
            <i className="fas fa-exclamation-circle mr-2"></i> {error}
          </div>
        )}

        <form className="space-y-5" onSubmit={handleSubmit}>
          {isSignup && (
            <>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Full Name</label>
                <input
                  type="text"
                  required
                  value={displayName}
                  onChange={(e) => setDisplayName(e.target.value)}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition"
                  placeholder="John Doe"
                />
              </div>
              {/* Role selection hidden to maintain academic integrity and controlled access */}
            </>
          )}

          <div>
            <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Email Address</label>
            <input
              type="email"
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition"
              placeholder="name@academy.com"
            />
          </div>

          <div>
            <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Password</label>
            <input
              type="password"
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition"
              placeholder="••••••••"
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-indigo-700 focus:ring-4 focus:ring-indigo-200 transition-all disabled:opacity-50 shadow-xl shadow-indigo-100"
          >
            {loading ? (
              <i className="fas fa-circle-notch animate-spin"></i>
            ) : (
              isSignup ? 'Create Academy Account' : 'Sign In'
            )}
          </button>
        </form>

        <div className="text-center pt-4 border-t border-slate-50">
          <p className="text-slate-500 text-sm">
            {isSignup ? 'Already have an account?' : "Don't have an account?"}{' '}
            <Link to={isSignup ? '/login' : '/signup'} className="text-indigo-600 font-bold hover:underline">
              {isSignup ? 'Log in' : 'Sign up'}
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
